INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8284070','Повертайся, солдате!','Музика: Сергій Родько Слова: Алла Бінцаровська. Виконує: Ірина Новомлинська','uk','ukraine_1991',NULL,NULL,'https://vk.com/public41907118','Пісню виконує Ірина Новомлинська (гурт "Струни серця").','З молитвою про тебе засинаю,
Думки про тебе вдень і уночі,
Я навіть твого імені не знаю,
Хоча імен у тебе - тисячі.
Ти вистояв сьогодні у двобої,
Хоч гільзами засіяна земля...
В твоєму серці - найсильніша зброя,
Вона на перемогу окриля.

Приспів:
Тільки ти повертайся, солдате,
Мій по духу і прагненню брате!
Зупинивши війни чорний дим,
Повертайся додому живим!!!

Нехай тебе, солдате, надихає
Небесна Сотня сміло йти у бій.
Гаряче серце куля не здолає
І не злякає "градів" буревій.
Ти - у думках мільйонів українців,
Ти не один - з тобою земляки!
Повік не пануватимуть чужинці,
На цій землі, що з Божої руки!

Приспів.','[''pisni.org.ua'', ''cat:devoted'', ''cat:patriotic'', ''Пісні присвячені окремим особам'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8284070'), datetime('now')),datetime('now'));
