INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8289171','Жити!','Музика: Анатолій Матвійчук Слова: Анатолій Матвійчук. Виконує: Анатолій Матвійчук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Струни тремтять так срібно
І пісня шукає небо,
І значить комусь потрібно
Усе, що на серці в тебе!
І лине душа крилата,
Мов птах у небесній сині -
Це зовсім не важко, брате,
Жити з ножем у спині!
Ти чуєш, гримлять салюти,
Кайдани розпались на порох,
І як нині важко збагнути,
Хто друг твій, а хто твій ворог.
Відкиньмо надії вчорашні,
Ілюзій рожеві скельця -
Не так бо вже, брате, й страшно -
Жити із кулею в серці!

Приспів:
Жити! Слава Україні!
Жити! Героям Слава!
Жити! Слава Україні!
Жити! Героям Слава!

Панує жахлива навала,
Не родить клоноване жито.
Нас сотні разів поховали,
А ми все продовжуєм жити!
Ми житимем вічно для того,
Щоб вірити й землю орати.
І зовсім неправда, їй Богу,
Що ні за що більше вмирати!

Приспів. (2)

Жити!','[''pisni.org.ua'', ''cat:euromaydan'', ''Пісні Євромайдану'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8289171'), datetime('now')),datetime('now'));
