INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_82817','Всякому городу','Слова: Григорій Сковорода. Виконує: Василь Жданкін','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Всякому городу нрав і права,
Всяка іміє свій ум голова.
Всякого прихоті водять за ніс,
Всякого манить к наживі свій біс.

Лев роздирає там вовка в куски,
Тут же вовк цапа скубе за виски,
Цап на городі капусту псує,
Всяк із другого дере за своє.

Кожен, хто вищий - той нижчого гне,
Дужчий безсильного давить і жме.
Бідний багатому вірний слуга,
Корчиться, гнеться пред ним, як дуга.

Всяк, хто не маже - то дуже скрипить,
Зто не лукавить - той ззаду сидить.
Кожного рот дере ложка суха,
Хто є на світі, щоб був без гріха?','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_82817'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_82817','Всякому городу','Всякому городу нрав і права,
Всяка іміє свій ум голова.
Всякого прихоті водять за ніс,
