INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8287219','Ангелику','Музика: Володимир Верней Слова: Олег Герман','uk','ukraine_1991',NULL,NULL,'інтернет',NULL,'Синку мій, прокинься, леле.
Хто ж для тебе постіль стеле,
із хмаринок слізьми миє...
Чом не разом нині ми є?..

Ой, матусю, люба нене,
Не тримай жалю на мене.
Я, мов свічка, став незрячим
І подзвінням тим, хто плаче...

Колихала тя'' під серцем,
Хрест на мене впав тепер цей,
По якому кулі били, -
Дай ми'', ангелику, сили.

То не мука, то не мука...
Я ж тобі зоставив внука.
Стане він навзаєм сина —
Не печалься, нене сива.

Ой, не стане, ой не буде...
Розриває туга груди.
Білим птахом в чорне небо
Полечу тепер до тебе...

Мамцю, нічка проминає...
Україна в нас одна є.
То ж тепер для вас і люду
Світлим ангелом я буду.','[''pisni.org.ua'', ''cat:euromaydan'', ''Пісні Євромайдану'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8287219'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8287219','Ангелику','Синку мій, прокинься, леле.
Хто ж для тебе постіль стеле,
із хмаринок слізьми миє...
Чом не разом нині ми є?..

Ой, матусю, люба нене,
Не тримай жалю на мене.
Я, мов свічка, став незрячим
І подзвінням тим, хто плаче...

Колихала тя'' під серцем,
Хрест на мене впав тепер цей,
По якому кулі били, -
Дай ми'', ангелику, сили.

То не мука, то не мука...
Я ж тобі зоставив внука.
Стане він навзаєм сина —
Не печалься, нене сива.

Ой, не стане, ой не буде...
