INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8281676','Рідна школа','Музика: Володимир Гуща Слова: невідомий. Виконує: Сергій Гуща','uk','ukraine_1991',NULL,'1996',NULL,'Пісня написана Гуща Володимиром Павловичем м. Радивилів у 1996 році','На шкільному порозі
Завмерли в сумному чеканні
Вчителі, школярі і батьки
Вже дорослих дітей,
То не в квітах живих
Урочистих лінійка прощальна
Під прощальну мелодію
Вмитих сльозою очей.

Приспів
Рідна школо, рідна школо,
Розлетяться як соколи,
Твої діти
В світанковий небокрай,
Розбудивши тишу ранню,
Продзвенить дзвінок останній -
Прощавай, моє дитинство,
Прощавай!

Нам, вчорашнім вже, учням
Багато про що є згадати.
Пролетіла як мить,
Лише слід залишили роки.
Наче вчора до школи
Привели нас мама і тато,
Наче вчора тулились
До них ми малі першачки.

Приспів.

Нас життя рознесе
По несходжених нами дорогах,
Наче листя з дерев
Понесе у незвіданий світ.
Та повернемось ми ще не раз
До шкільного порогу,
Щоб з дитинством зустрітись
Хоча би на мить...

Приспів','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8281676'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8281676','Рідна школа','На шкільному порозі
Завмерли в сумному чеканні
Вчителі, школярі і батьки
Вже дорослих дітей,
То не в квітах живих
Урочистих лінійка прощальна
Під прощальну мелодію
Вмитих сльозою очей.

Приспів
Рідна школо, рідна школо,
Розлетяться як соколи,
Твої діти
В світанковий небокрай,
Розбудивши тишу ранню,
Продзвенить дзвінок останній -
Прощавай, моє дитинство,
Прощавай!

Нам, вчорашнім вже, учням
Багато про що є згадати.
Пролетіла як мить,
Лише слід залишили роки.
Наче вчора до школи
Привели нас мама і тато,
Наче вчора тулились
До них ми малі першачки.

Приспів.

Нас життя рознесе
По несходжених нами дорогах,
Наче листя з дерев
Понесе у незвіданий світ.
Та повернемось ми ще не раз
До шкільного порогу,
Щоб з дитинством зустрітись
Хоча би на мить...

Приспів');
