INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8289450','Зустрічайте коляду!','Слова: Л. Антонова','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Хтось веселий надпис вивів
На тоненькому льоду:
"Гей! Свята прийшли у гості!
Зустрічайте коляду!"

Трійка коней прудконогих
Мчить по білому сніжку —
Коляда везе в санчатах
Сто гостинців у мішку!

Чуєш, дзвоники співають:
Тілі-тілі-тілі-бом!
Ідуть ряжені на конях
Нас вітати із Різдвом!','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Колядки'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8289450'), datetime('now')),datetime('now'));
