INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_829373','Ой пише-пише да Гетьман Мазепа','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'1. Співає зі старосвітською бандурою кобзар Микола Будник: Воскресні та Спасительні пісні © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2003. 2. Українські релігійні роздуми про Спасіння © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2003.','Слухати також Думу Івана Степановича Мазепи "Всі покою щиро прагнуть". Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Господа Милосердного прохали та благали. Як трудно Брате Україну боронить. Заплакала Україна така її Доля. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Ой пише-пише да Гетьман Мазепа до Палія листи
Ой приїдь приїдь Палію Семене на бенкет до мене

Ой вже Семен ой вже Палієнко на подвір''я прибуває
А там його вельможний Мазепа зустрічає
Ой там його вельможний Мазепа вітає

Гей вельможний мій Семене Брате
Полковниче мій вірненький гей
Ой дай Радоньку мені гей

Ой обсідають з усіх боків вороги
Що найперший враг Петро-самодержець

Ой Палію Семене Полковниче мій
Ой сказать тобі словами не можу
Як трудно Брате Україну боронить

От так і рве тая сила його на Україну
Всю Україну обставив своїми гарнізонами гей
Воєводи-свавільці як і сам Петро
Опричники України
Так і норовлять нарід у ярмо своє запрягти

І не можу Брате я своєї старшини
під рукою міцно тримати
Як худоба розбрідаєцця в усі краї  в усі боки
Батога одного любить

Не можу Брате я зібрати своїх старшин
під міцною рукою
Рабськеє начало ніяк не переборецця','[''pisni.org.ua'', ''cat:dumy'', ''cat:istorychni'', ''cat:kozacki'', ''cat:suspilno-politychni'', ''Думи'', ''Історичні пісні'', ''Козацькі пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_829373'), datetime('now')),datetime('now'));
