INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8285575','Весняночка','(Лине струмочками). Музика: Дмитро Луценко Слова: Ілля Віленський','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Лине струмочками,
Грає дзвіночками,
Кличе маляток
