INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_829052','Буде ярмак, буде','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Самвидавний туристський пісенник: Там на Лемковині помедже горами. - Літо 1981.','Вказаний у джерелі пісенник створений українцем з Польщі Лехом Ляхом. Ймовірно, що обробка тексту й мелодії, підбір акордів здійснені ним. Діалектизми: в Пряшові-м - в Пряшові я; дашто - дещо, щось; добрі - добре (тут - вигідно); домів - додому; кед - коли, якщо; керпці - личаки, постоли; ліпшу - кращу; не нашов - не знайшов; нескоро-зме - ми нескоро; нич - нічого; півдруга - півтора; под - іди, йди; ся розходжали - розходилися; тівко - стільки; туньо - дешево; тя - тебе; ци - чи; юж - вже; ярмак - ярмарок.','Бу_де ярмак, буде в Пряшові в середу,
Та я свою жену на ярмак поведу.
Кед буде дорого, продам тя, небого,
Кед буде за туньо, под домів, ґаздиньо!

Нескоро-зме пришли, юж ся розходжали,
А за мою стару мало мі давали.
Єден мі обіцяв півдруга таляра,
Другий ані тівко, бо є дуже стара.

В Пряшові-м не нашов купця богатого,
Поведу тя, жено, аж до Гуменного.
Кед тя добрі продам, а же нич не втрачу,
Куплю собі ліпшу, хоч дашто доплачу.

Жену я там продав, але і заплакав:
Та хто же мі буде мої керпці латав?
Піду знов на ярмак, куплю тя, небого,
Ци будеш за туньо, або за дорого!','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_829052'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_829052','Буде ярмак, буде','Бу_де ярмак, буде в Пряшові в середу,
Та я свою жену на ярмак поведу.
Кед буде дорого, продам тя, небого,
Кед буде за туньо, под домів, ґаздиньо!

Нескоро-зме пришли, юж ся розходжали,
А за мою стару мало мі давали.
Єден мі обіцяв півдруга таляра,
Другий ані тівко, бо є дуже стара.

В Пряшові-м не нашов купця богатого,
Поведу тя, жено, аж до Гуменного.
Кед тя добрі продам, а же нич не втрачу,
Куплю собі ліпшу, хоч дашто доплачу.

Жену я там продав, але і заплакав:
Та хто же мі буде мої керпці латав?
Піду знов на ярмак, куплю тя, небого,
Ци будеш за туньо, або за дорого!');
