INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8291103','Гімн Україні','Музика: Олександр Морщавка Слова: Людмила Паниченко. Виконує: Олександр Морщавка','uk','ukraine_1991',NULL,NULL,'Диск "Пісня серця"',NULL,'Земля легенд, оспівана в піснях,
Вінок терновий в кетягах калини.
Шлях до свободи - покручами шлях
Ти йшла по ньому мати-Україно.

Приспів:
Степи квітучі, ниви і поля, поля...
Край волелюбний, пісня солов''їна.
Усіяна талантами земля, земля...
Дарована Всевишнім Україна!
Україна! Україна!

Омріяна, прославлена в віках
Свобода, що розквітла на руїні.
За неї віддали своє життя
Сини твої найкращі, Україно!

Приспів.

Козацький дух і пісня кобзаря
Народу не дадуть стать на коліна.
На обрії зійшла нова зоря -
Велика, суверенна Україна!

Блакитно-жовтий прапор навіки зорить -
Одвічний колір неба і колосся.
Тризуб яскраво золотом горить, горить!
Задумане століттями - збулося, все збулося!
Відбулося!','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8291103'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8291103','Гімн Україні','Земля легенд, оспівана в піснях,
Вінок терновий в кетягах калини.
Шлях до свободи - покручами шлях
Ти йшла по ньому мати-Україно.

