INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_828777','Львів - місто дощів','Музика: Павло Соколовський Слова: Андрій Бондарев. Виконує: Limit','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Приспів:
Львів - місто дощів,
Львів - місто моїх снів:
Запах кав''ярень,
Бруківки дощовий блиск.

Львів - замок на горі,
Львів - нічнії вогні,
Сплячі леви,
Та затишок старих вулиць.

Куплет  1:
Західна столиця нашої Держави
Запитайте нас: "Як справи?",
А ми Вам Високий Замок стоїть,
Отже, чудова ця мить,
Бо все як раніше - нічого не міняється
Місто таким самим залишається.
Сімсотрічна історія,
Карпатська територія,
Це моє місто - Львів,
І не потрібно тут слів
Тут самі почуття
Це знаєш ти, це знаю я
І всі, хто ріс з нами,
Хто гуляв під дощами,
Хто брав собі каву
Сідав до тебе на лаву,
Щоб сказати все і одночасно нічого.
Так, це звична розмова
Для нас - львів''ян,
Для панів та дам,
Для тих, хто з містом як одне ціле,
Для тих, кому футбол - зелене, біле.
так буде завжди,
не зможу сказати "Ні"
На запитання "Ти любиш дощі?",
Бо це є стан моєї душі.

Приспів.

Куплет  2:
Одне слово - Львів.
Західна столиця нашої  Держави.
Ми зростали з нею, вона зростала з нами.
І навіть часом здається,
що без цього міста серце вже не б''ється.
Кожна вулиця - це куточок моєї душі.
Їх настільки багато, що в ній можна заблукати.
Про це місто поети складають вірші.
І не дарма - тут є про що складати.
Одне слово - Львів.
Місто царських звірів,
Місто княжої краси.
В дчуйте її в повній мірі.
Ми вам представляємо перлину України.
Це наше місто: будівлі, парки й стіни.
Це все р дне з дитинства, і знайоме усім.
Це наше місто, і це наш дім.
Отже пісня кінчається, тільки декілька слів,
І ми з вами прощаємось, залишається Львів.

Приспів. (2)','[''pisni.org.ua'', ''cat:lviv'', ''Пісні про Львів'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_828777'), datetime('now')),datetime('now'));
