INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8289312','У лісі народилася ялиночка','Музика: Леонід Бекман Слова: Раїса Кудашева','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У лісі народилася,
У лісі і зросла.
Завжди струнка ялинонька
Зеленою була.

Співала Завірюха їй:
"Ялинонько, бай-бай!"
Вкладався снігом Сніговій,
Вкривав зимовий гай.

Там заєць із зайчатами
Під гілками стрибав,
Тоді як вовк, голодний вовк
У полі десь гасав.

Під новий рік Морозко Дід
Прийшов в казковий ліс,
Зрубав красу-ялиноньку
І дітворі поніс.

І ось в вбранні святковому
На радощі дітей
Ялинкою казковою
До нас вона іде.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8289312'), datetime('now')),datetime('now'));
