INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8289307','Білі сніжинки','Музика: Геннадій Гладков Слова: Ігор Шаферан','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Білі сніжинки кружляють з ранку,
Виросли замети посеред двору.
Стала від сніжинок вулиця світліше,
Тільки одягатися потрібно тепліше.

Просто неможливо зиму не любити,
Скоро будемо бабу снігову ліпити.
Якщо на прогулянці у сніг, що ми впадемо,
Встанемо, стряхнемось і знову підемо.

Привезуть з лісу ялинку в дитячий сад,
Дід Мороз привітає зі святом дітей.
Десять раз на тиждень ми рахуємо дні,
Щоб запалилися швидше яскраві вогні.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8289307'), datetime('now')),datetime('now'));
