INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8289154','Герої не вмирають - вмирають вороги!','Музика: Перша Лінія Слова: Перша Лінія. Виконує: Перша Лінія','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Герої не вмирають -      |
Вмирають вороги!         | (3)

Герої не вмирають -
Вони летять на небо,
І там дивляться на нас,
На життя і міста.
Поруч в наших серцях,
Завжди в душі поруч.
Промінням світла сонця,
Вітром у горах.

Ще не змили весь порох
І кров з бруківки.
І ще не знаємо точно
Полягло їх скільки.
Та йдемо далі,
В сірих справах будня,
Ми, ніби люди всі,
Та людяність відсутня.
Щоб ми ділили й нищили,
Загинули за те вони?
Там, де була свобода,
Враз оселились демони.
І лиш на мить прокинулись,
Піднялися з колін,
Та прагнення лишилося
Тільки прагненням до змін.

У нас одна надія -
Діяти сьогодні,
Честь і Хвала навік
Небесній Сотні!
Пробачте нам слова наші,
Думки нікчемні.
Сподіваюся, Ваш подвиг
Буде недаремним!

Летіть, Наші Герої,      |
Знайдіть свій спокій!    |
А ми за вас назад        |
Не зробимо ні кроку,     |
І будем боронити         |
Україну поки             |
Тіла наші вогонь         |
Не перетворить на попіл. | (2)','[''pisni.org.ua'', ''cat:euromaydan'', ''Пісні Євромайдану'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8289154'), datetime('now')),datetime('now'));
