INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8290219','Гей, ти, дубе зелененький','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Гей ти дубе зелененький - чому не розвився? |
Зима була студененька - я заморозився.      | (2)
Зима була студененька, літо холоднеє,       |
Не могло ся розвивати листя широкеє.        | (2)
А Іване молоденьке, Іване, Йваниня,         |
Зоводь мене за ручину й домів поведи ня.    | (2)
Гей, домів поведи ня, поклади ня спати.
Тихо, діти, не шуміти - най ся проспить мати.
Та як тую Гоцулочку почую, почую,           |
По три ночки й по чотири в дома не ночую.   | (2)
Гей у дома не ночую, бо ня нич не гріє,     |
Та я їду до милої - краще вона діє.         | (2)
А й не добре чоловіка шоферика мати,
Він не хоче старій бабі на бороді спати.
Та як ввидить на дорозі молоду дівчину      |
І руками і ногами тормозить машину.         | (2)
А як піду на вулицю - думаю дурницю,        |
Як побачу у червоній сукні молодицю,        | (2)
Молодице моя люба, обернися сюда,           |
А як ти ся обертала в ночі біля дуба.       | (2)
Ой, чиє це весілєчко, чиє це, чиє це?
Молода ся озиває: Моє це! Моє це!
Ой, чиє це весілєчко, чи не молодого?       |
Молода ся й озиває: Чоловіка мого!          | (2)','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8290219'), datetime('now')),datetime('now'));
