INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8296654','Неопалима Купина','(Ти сієш зерна доброти). Українська народна пісня','uk','ukraine_1991',NULL,'2012','Співаник на прощу. Вигода. Стрий-Зарваниця, 2012 рік.',NULL,'Ти сієш зерна доброти,
Пречиста Матінко Маріє.
Його топтали вороги,
Лишили вірних без надії.

Приспів:
Благословенна будь,
Неопалима Купино,
У світі горя, сліз і мук
Хай проросте Твоє зерно.

Пречиста Діво пресвята,
Ти всі незгоди відвертаєш.
Твоя корона золота,
Неначе сонце правди сяє.

Приспів.

Все християнство крізь віки
До Тебе, Матінко, стремиться.
Ти всіх вітаєш залюбки,
Небесна і земна Царице.

Приспів.

Усі народи на Землі
Твоє Різдво благословляють.
Небесні ангели в Раю
Тебе з Різдвом святі вітають.

Приспів.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8296654'), datetime('now')),datetime('now'));
