INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_829501','Козацький марш','(Хтось та й вродиться з нас нещасливо). Музика: Андрій Чернюк Слова: Ігор Чернюк. Виконує: Андрій Чернюк, Микола Сікора','uk','ukr_ssr_1919_1991',NULL,'1989',NULL,'Вперше прозвучала в 1989 році на фестивалі Червона Рута. В усіх пісенниках зазначена як народна. Подаю все в авторському варіанті. (Андрій Чернюк тел.80674406889)....Ще цю пісню з оркестром народних інструмент виконує Микола Сікора, ще я чув її у виконанні різних хорів, але там мелодія та іноді слова перероблені. Акорди (варіант 2) надав Taras Hryvul.','Em                   Н       Em     D
Хтось та й вродиться з нас нещасливо,
Я не знаю, яким був мій рід.
Пресвята Богородице Діво,
Вирушаєм сьогодні в похід.

Затріпочуть хоруговки крилами,
Запорізький лунатиме марш.
Hе заручені ми із милими,
Увесь полк неодружений наш.

Помолюсь я і в путь, так, як водиться,
Треба йти до чужих вже сторон -
Борони Ти мене, Богородице,
Щоби я не потрапив в полон.

А якщо ненароком загину,
Хай мене поховають за дня,
Понесуть на руках побратими,
Поведуть вороного коня.

Коли вдарять нараз із мушкетів,
Загуде полковий тулумбас;
Дух мій, Діво, тоді вже відлетить
Аж на Січ, в Україну, до нас.

Хтось та й вродиться з нас нещасливо,
Я не знаю, яким був мій рід.
Пресвята Богородице Діво,
Вирушаєм сьогодні в похід.

Акорди (варіант 2):
Хтось та й вродиться з нас нещасли_во,
Я не знаю, яким був мій рід.
Пресвята Богородице Діво,
Вирушаєм сьогодні в похід.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_829501'), datetime('now')),datetime('now'));
