INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_829654','Славен єс Боже по всему Сьвіту','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло. Українські реліґійні роздуми про Воскресіння, Неволю і Спасіння. Пісні-плачі Сокола-Прадіда. Сам Біг Небесний Службоньку служит. Йа поза Стілю сидьи Сьвйитії. Богу молився щоб Світ творився. Ци вни си мольи Сьвйитому Різдву. Службоньку служив Слізоньку вронив. Послужи мене встріть Николаю. Ой Ми зіслані на признаванє. Гой поза Стіля самі Світії. Радї Радочку Первовічную. Ци держи Віру Старовіцькую? Чи починає по Старосвіцькому? Що вже ж тоді Правда правда померкла. Нема в світі Правди. Ишов перейшов Місяць по Небі На Горі Горі Топірці Дзвені Ой в Ліску в Ліску на Жовтім Піску Ой в Лїску Лїску на Жовтім Піску Ой в Чистім Поли блисько Дороги Ой сів Христос вечеряти Щедрий Вечір Пане Господару а на Твоїм Двору Славен єс Боже по всему Сьвіту Славен єс славен єси Боже по всему й світу Ци Громи громє ци Дзвони дзвонє Чи є чи нема Пан Сподар в Дома Чи є чи нема Господар в Дома Ци вни си клоньи Сьвйитому Збору. З Збором ідемо Полон несемо На Горі Горі Топірцї Дзвенї Ой в Лїску Лїску на Жовтім Піску Ой Добрий Вечір Пане Господарю ми в Тебе Славен єс Боже по всему Сьвіту А з Полянойки до Царинойки. Виходжай Зборе з Села на Поле. На Синих Морях на Перевозах. Там Сїм-сот Душок я перевозив. Бездільне Своє та Безрідне Ясне Соколя утеряв. А десь ми поверх всякої міри гріха набрали. А єсть це нас Отцева-та-матчина Молитва покарала. Нема в світі Правди не зіскати. Що вже тепер Правда стала неправдою жити. Що вже кінець Сьвіту дуже приблизився. Тільки в світі Правди як Отець-Рідна-Мати. Ми Кривого Танцю йдемо У Чистому Степу собі Живности доставати. Байді Молодому Мед-горілку пити. Многая Літа да посієм Жито. Приїдь Синочок напийсь Води. Ой устань же Козаченьку. Господа Милосердного прохали та благали. Сумний Святий Вечір (1) Сумний Святий Вечір (2) Радуйся Земле Коляда іде! Св. Микола символом Прадіда й Місяця. Оба Свята, — св. Михайла і св. Миколи, — вдаряють Місячною символікою. Постать св. Николая (Николи, Миколи) — це образ, схожий до св. Михайла, прикрашений мистецько складеною Місячною символікою. Ось приклад Колядки, — Славен єс Боже по всему Сьвіту, — де співають, як Господь посилає послугу свою, св. Петра, встріть Николу, котрого кличе в гостину до Ґазди, де вже сам гостює з св. Петром. Меч в одній руці у св. Николи — це Новий Місяць, Кубок у другій — це Повня Місяця; Теплий Вітрик, Дрібний Дощик — це атрибути Весняного Місяця, його добродійна Астральна еманація. Малу-ж годинку перегодивши Тай уже иде Сьвйитий Никола Никола идет тай Весну ведет Йа Весну ведет а Зимку женет Так Весну ведет Крутим Колачем А Зимку женет Ясненьким Мечем Ясненьким Мечем Теплим Вітриком Теплим Вітриком Дрибним Дожджиком А на Николї Сьвйита Коруна А в ручках йиму Золотий Кубок Але в цій Колядці можуть бути поєднані Астральні порухи. Меч, себто Новий Місяць, його доповненням є символ Повні Місяця — Кубок; Свята Коруна — це Сонце, а Дрібний Дощик є символом Господа і в деяких Українських мітологічних образцях символ Зорі. Це відповідає одному з найкрасших мітологічних Колядкових образців, Трійці: Місяць, Сонце і Дощик — сам Милий Господь Бог. Теплий Вітрик можна б також уважати за символ Господа. Пригадується біблійна аналогія: Тихий Вітрець як символ Господа. Сам св. Никола — це символ Прадіда і послідовно: уособлення Місяця. В світовій мітології Прадід є символом Місяця або Сонця. Наше дослідження виказує, що в Коляді і Щедрім Вечері дуже наголошується шанування Прадіда й Місяця. Св. Микола і містична Купіль Господа. Подібна з повищою інша Колядка: А в Нашого Дядька да в Його Дому. А в Нашого Дядька да в Його Дому А в Нашего Дядька да в Його Дому Святий Вечер! В Кінець Стола там стояв Микола Підперся Мечем під праве плече А в лівій руці Кубочок держав А з того Кубочка Сльоза капнула А з тії Сльози Дунай розлився А в тім Дунаю Христос купався Христос купався на муку здався!... Таємна Сльоза з Кубка, з якого Дунай розлився, а в нім Христос купався, — це рівновартність Дощику з Неба. Цей дуже популярний Колядковий мотив буде окремо обговорено. Сльози і Купіль Господа. Плач Сокола. Службоньку служив Слізоньку вронив: А в Горі в Горі в Глибокім Зворі А в Нашого Дядька да в Його Дому У Пана Івана да за Його Сталом Листки з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Прадід і Лицарі. Прабатько – Вчитель, Лицар і Вірник Божий. Сльози і Купіль Господа. Плач Сокола. Службоньку служив Слізоньку вронив. Свята, Тайна, Вечеря 6.01 - Містичний час Різдва Світа. Що означає Святий Збір? Традиції самогуртування: Cвятий Збір.','Cлавен єс Боже по всему Сьвіту
Славен єст!
Йа по всїх церквах по монастирях
Йа ти є славний наш Ґосподарю
Наш Ґосподарю Пане Федоре
Йикий ти славний в Нашій Громадї
В Нашій Громадї тай у Порадї!

В нашого Ґазди Пана Федора
Новії Доми Тисові Столи
Йа поза Стілю сидьи Сьвйитії
Котрі Сьвйитії Господь из Петром

Так казав Господь свому Петрови
А ци всї ви тут мої Сьвйитії
Ой лише нима одного Сьвйитка
Й одного Сьвйитка Сьвйит Николая

Ти Сьвйитий Петре послуго-ж моя
Послужи мене встріть Николаю

Малу-ж годинку перегодивши
Тай уже иде Сьвйитий Никола
Никола идет тай Весну ведет
Йа Весну ведет а Зимку женет
Так Весну ведет Крутим Колачем
А Зимку женет Ясненьким Мечем
Ясненьким Мечем Теплим Вітриком
Теплим Вітриком Дрибним Дожджиком
А на Николї Сьвйита Коруна
А в ручках йиму Золотий Кубок

Прийшов Никола навперед Бога
Прощьий ми Боже шо я зогрішив
Шо я зогрішив шо я си барив
На Синих Морах на Перевозах
Я перевозив Там Сїмсот Душок

Сьвйитий Господи Исусе Христе
Видки си взьили Буйнії Вітри
Тихий Корабіль вони звихнули
Йа в Сине Море перевернули
Тоти душечки Там потапали
Там потапали тай ни пропали
Бо їх ратував Сьвйитий Никола

Лиш одна душка в Море потала
В Море потала бо грішна була
Вна зогрішила Вітцу-й-Матери
За Недїленьку ни шьинувала
Старшому Вітцю вна відрікала

И та душечка Там ни пропала
Тай нирав за нев Свйитий Никола
У Сине Море там тричи ді Дна
И тай душечка Там ни пропала
Бо-ж ї ратував Сьвйитий Никола
Бо за нев нирав Сьвйитий Никола
У Сине Море тай тричи ді Дна

Наш Ґосподарю Пане Федору
Шо тепер робит ся наша верства

Ци держи Віру Старовіцькую
Старовіцькую тай Старих Людий
Ци вни си мольи Сьвйитому Різдву
Ци вни си клоньи Сьвйитому Збору
Ци держи Віру Старовіцькую

Вже тепер ни так йик було давно
Йик було давно за Старих Людий
Бо син на вітця пориваєт си
Донька з матїрев суперечит си
А брат на брата нїж винимаєт
Сестра на сестру чьирів шукаєт
Сусїд сусїда до війта вдаєт
В війта неправдов йиго обмовльит

Так си минула Стара Правдочка
Стара Правдочка тай Старих Людий

Вінчуємо... (і т.д.)','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''cat:suspilno-politychni'', ''Соціально-побутові пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_829654'), datetime('now')),datetime('now'));
