INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8294116','Вересневі дзвоники','Музика: Анатолій Салогуб Слова: Анатолій Салогуб. Виконує: Анатолій Салогуб','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Встали ми раненько на зорі,
У портфелі склали букварі.
Весело сьогодні дітворі,
Нас назвали вперше школярі.

Приспів.
Вересневі дзвоники
Кличуть нас у клас.
Наша рідна школа
Вже чекає нас.
Вересневі дзвоники,
Ви такі дзвінкі,
Вересневі дзвоники
Хай почують всі.

Нас садок дитячий зустрічав,
Нам тепло своє подарував.
Непомітно швидко підросли,
Вже до школи вчитись ми прийшли.

Приспів','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8294116'), datetime('now')),datetime('now'));
