INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8302052','Ніколи','Музика: Єжі Петербурський Слова: Анджей Власт. Виконує: Люцина Хворост','uk','ukr_ssr_1919_1991',NULL,'1930',NULL,'Українська версія польського танґо 1930-х рр. (музика Єжі Петербурзького, польський текст Анджея Власта, український переклад Люцини Хворост. Аранжування Дмитра Новичонка, звукозапис студії ForMoreProduction.','Дивлюсь я на твою світлину,
Ту, що ти прислав мені.
І знов, і знов думками лину
В неповторні наші дні, -
Хоч все минуло, здається,
Я збагнула, здається,
І забула усе.

Приспів:
Ніколи
Не почую тебе й не озвусь,
Ніколи
Не торкну твоїх рук, твоїх вуст...
І знаєш,
Біль розлуки зі мною навік,
Не забути обіймів твоїх
Святість і гріх
Ніколи!
Ніколи -
Як жорстоко це слово звучить!
Ніколи -
Та це правда, а правда гірчить...
Ти щезнув,
Розчинився, як привид, як дим,
І не зможу змиритись я з цим
В серці своїм
Ніколи.

Невже цей слід з душі не стерти,
Слід задавнених горінь?!
Ти був усім - а хто тепер ти?
Тільки спогад, тільки тінь...
Що ж, прощавай, моє кохання,
Моє розчарування,
Палкого серця сон.

Приспів.','[''pisni.org.ua'', ''cat:dances'', ''cat:tango'', ''Пісні до танцю'', ''Танґо'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8302052'), datetime('now')),datetime('now'));
