INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8299052','Небесна Сотня України','Музика: Володимир Домшинський Слова: Мирослав Бойчук. Виконує: Василь Михайлович','uk','ukraine_1991',NULL,NULL,'Записано на студії "Дзвони"','Оранжування Романа Калина. Пісня написана для документального фільму "Розстріляна весна". Режисер Мирослав Бойчук. Виконує: Василь Михайлович.','Прийшла весна у білосніжнім цвітті,
Вже двісті літ відзначив наш Тарас,
І свята Пасхи дочекались діти,
Але без Вас, але уже без Вас...
А літній день задзвонить випускними,
Запросить молодят весільний вальс,
Зійдуть поля хлібами золотими,
Але без Вас, але уже без Вас...

Приспів:
Небесна Сотня України,
Країни-мачухи сини,
Небесна Сотня України
Приходить матерям у сни.
Небесні наші Сестри й Браття,
Що вічно житимуть в серцях...
Небесна Сотня України,
Пшениці й неба мирний стяг.

Прийде врожаєм українська осінь
І чийсь малюк піде у перший клас,
Блакитніє волошка у колоссі,
Але без Вас, але, на жаль, без Вас...
І снігом пам''яті зимова казка,
Проляже квітом в той буремний час...
Христовим святом знов запахне Паска
Посвячена для нас уже без Вас...

Приспів','[''pisni.org.ua'', ''cat:devoted'', ''Пісні присвячені окремим особам'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8299052'), datetime('now')),datetime('now'));
