INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8300103','Серця стук','Музика: Ірина Федишин Слова: Ірина Федишин. Виконує: Ірина Федишин','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Тук-тук! Серця стук!
Тук-тук! Серця стук!
Тук-тук! Серця стук!
Тук-тук! Серця стук!

Котиться сльоза і душа сумна,
Згасла вже зоря, а тебе нема...
Нащо ти пішов? Нащо ти знайшов
Іншу? А мене, а мою любов...

Приспів:
Чуєш, кажу: Відпусти!
Не тримай мене! Іди!
Все! Не буде більше сліз!
Тук-тук! Серця стук!
Тук-тук! Серця стук!
Серця стук!.. Серця стук!..

Світ розбитих мрій, світ моїх надій
Завела зима - там тепла нема..
Знаю, що любов не була моя,
Знаю, що любов - це була лиш гра...

Приспів.

Іграшка була у твоїх руках,
Божевільна я, немов дикий птах,
Все минуло,
Тільки почуття не розіб''єш,
Не розіб''єш!..

Приспів','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8300103'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8300103','Серця стук','Тук-тук! Серця стук!
Тук-тук! Серця стук!
Тук-тук! Серця стук!
Тук-тук! Серця стук!

Котиться сльоза і душа сумна,
Згасла вже зоря, а тебе нема...
Нащо ти пішов? Нащо ти знайшов
Іншу? А мене, а мою любов...

Приспів:
Чуєш, кажу: Відпусти!
Не тримай мене! Іди!
Все! Не буде більше сліз!
Тук-тук! Серця стук!
Тук-тук! Серця стук!
Серця стук!.. Серця стук!..

Світ розбитих мрій, світ моїх надій
Завела зима - там тепла нема..
Знаю, що любов не була моя,
Знаю, що любов - це була лиш гра...

Приспів.

Іграшка була у твоїх руках,
Божевільна я, немов дикий птах,
Все минуло,
Тільки почуття не розіб''єш,
Не розіб''єш!..

Приспів');
