INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8301909','Іде козацька сотня','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Іде козацька сотня,
Курявину здійма,
Луна козацька пісня,
Тужлива та сумна
І раптом славний Джура
Напрягся, мов струна,
І піснею пролунала
Промова отака:

Приспів:
Ти не журись, козаче,
З тобою слава й вдача,
Ще будуть перемоги,
І буде не одна,
Доки з тобою поруч
Твій вірний друг - Джура!

Пливуть славетні чайки,
Нудьгують козаки,
Блукають їхні думки
По морю, мов човни,
Обличчя геть сумні.
Підвівся славний Джура -
Статура ватажка,
Над морем пролунала
Промова отака:

Приспів.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8301909'), datetime('now')),datetime('now'));
