INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8295013','Вівати','(Ой, не плач, молода). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Галина Дудар. З глибин джерел народних. Конкурсна робота. Моя батьківщина - Україна. Тернопіль, 2014 р.',NULL,'Ой, не плач, молода,
Нехай дружка плаче,
Вона би ся віддавала,
Аж ї серце скаче.

Молодий молоду
Посадив на льоду.
Ой, чекай, молода,
Забереться вода.

Ото собі дівку вибрав,
Ото си сподобав,
Що ї кури не доїли.
Когут не додзьобав.

А кури не їли,
А когут не дзьобав,
Така була гарна,
Що си не сподобав.

Ой, чия ж то дівчинонька
В зеленій спідниці?
Вона так ся гонорує,
Як жаба в криниці.

Чого дружки не співають?
Голосу не мають?
Наїлися бараболь,
Ледве віддихають.

Бараболі ми не їли,
А гречану кашу,
А тепер ми не співаєм,
Бо не маєм часу.

Пішов дружба на базар,
Вкупив собі чайник,
Причепив си на живіт,
Каже жи начальник.

Ой, чий же то парубочок,
Чи не мого вуйка?
А він так ся розспівав,
Аж під носом булька.

Ой, дружки, дружечки,
Що ви наробили,
Що ви мою косу
На вітер пустили?

На вітер пустили,
Тепер заплетіте,
На й я погуляю,
Так як інші діти.

Бо іншії діти
Підуть в клуб гуляти,
А я молоденька -
дитя колисати.

Ой, спи, дитя, засинай си,
Я буду співати,
А як добре заснеш,
Піду в клуб гуляти.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8295013'), datetime('now')),datetime('now'));
