INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_829676','Тече Річка Невеличка Щедрий Вечір','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога: Яблучко © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Хто пише на Тому Листочку? Сотворення Сьвіта (сьвітла) як Святе, Сьите, Письмо. Творення як акт письма, прочитання, проспівування. Світ як текст, письмо, пісня. Зауважити ряд "Світ" – "Світло" – "Сьитий" – "Святий". Сьвіт містить Вість – Віть – Вісь – Сіть - Всі. Сьвітло містить ще Тіло, Тло, Сіль, Тісто, Стіл.... Ідея Почину Світа і його Творця. Колядки як Міти про Почин Світа, Первовічне життя. Два роди світотворних Колядок. Традиції Спасителя і старинна ідея Бога. Реліґійні роздуми про Сотворення Світа. Пракультурна ідеологія: поклін Творцеві. Первовічне Дерево і ідеал духового Творця Світа. Зродження Райського Дерева. Духові єства на Райськім Дереві. Райське Дерево символом Місяця. Троїста Астральна світотворча сила. Віра в Бога Творця і мітологійні ідеали. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі)... Великдень... Зелені Свята (Трійця)... Івана Купала Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. На Тім Листку написано Щедрий Вечір. А в Нашого Пана Отця Золотії Ворітця А в Нашого Хазяїна тай Ворота Нові А з Клену Листу нападало Ми си изийшли в Вашим Домочку На Ріці на Бистрици плинуть Листи Написані Ой на Річці на Госоці Ой на Річці на Ордані(1) Ой на Річці на Ордані(2) Там у Нашого Пана Сподара Тече Річка Невеличка Щедрий Вечір Щож нам було з Світа Почитку Боже Наш Що й у Нашого Пан-Отця Золотії Ворітця Листойко пише Гадки гадає. Івана Купала тай в Воду упала. Ой там Маруся Воли гнала Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Колядки про Почин Світа. Первовічне Дерево і ідеал духового Творця Світа. Ідеал щастя. ― Храм ідеалів. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції. Рокове Коло.','Тече Річка Невеличка Щедрий Вечір Добрий Вечір!
На тій Річці плине Листочок Щедрий Вечір Добрий Вечір!
Плине Листочок Яблуньовий Щедрий Вечір Добрий Вечір!
На тім Листку написано Щедрий Вечір Добрий Вечір!
Написано Сонце й Місяць Щедрий Вечір Добрий Вечір!
А що Місяць то Господар Щедрий Вечір Добрий Вечір!
Ясне Сонце Господиня Щедрий Вечір Добрий Вечір!
Ясні Зірки Його Дітки Щедрий Вечір Добрий Вечір!','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:philosophic'', ''cat:shchedrivky'', ''Колядки'', ''Філософські пісні'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_829676'), datetime('now')),datetime('now'));
