INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_830552','Заметіль','(Сніг впаде на поріг....). Музика: Софія Федина Слова: Софія Федина. Виконує: Софія Федина','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Сніг впаде на поріг,
І часу біг не зупинити...
Дні з приходом зими
Знайшли кольори одної миті.

Приспів:
Я - сьогодні одна,
А завтра зима прийде з тобою.
Ти - сьогодні один,
А завтра навік будеш зі мною.
Заметіль...
Серце вибирає перший крок.
В вишині
Пісня ця лунає
Для нас двох.

Сніг впаде на поріг,
І вже новий рік ступає стиха.
Дзвін останніх годин,
Немов серпантин злітає тихо...

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_830552'), datetime('now')),datetime('now'));
