INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_830272','Ой не куй, зозуле','Українська народна пісня','uk','ukraine_1991',NULL,'1997','Шевченків край: Історико-культурологічні нариси. - К., 2005. С. 453.','Записали Я. Пришедько, М. Музика, Є. Шевченко, П. Зубченко у с. Великий Хутір Драбівського району Черкаської області від бандуриста Михайла Коваля та його односельців 1997 року. Розшифрував К. Міщенко. Пісня з добірки Леопольда Ященка.','Ой не куй, зозуле, да й по діброві,
Да й не збуди мене, молодо(ї).

Бо я й молода да й не гуляла,
Бо мене матінка й не пуска(ла).

Бо мене й матінка да й не пускала -
У новій коморі зачиня(ла).

У новій коморі да й зачиняла,
Золотим замочком замика(ла).

Золотим замочком да й замикала,
Шовковим шнурочком зав''яза(ла).

Ой посидь же, доню, да й у темниці,
Поки й розійдуться вечорни(ці).

Поки й розійдуться да й вечорниці,
Поки ляжуть спати чарівни(ці).

Пусти ж мене, мамо, да й погуляти,
Бо вже чарівниці лягли спа(ти).

Тільки мій миленький по двору ходить,
Вороного коня за повід во(дить).','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_830272'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_830272','Ой не куй, зозуле','Ой не куй, зозуле, да й по діброві,
Да й не збуди мене, молодо(ї).

Бо я й молода да й не гуляла,
Бо мене матінка й не пуска(ла).

Бо мене й матінка да й не пускала -
У новій коморі зачиня(ла).

У новій коморі да й зачиняла,
Золотим замочком замика(ла).

Золотим замочком да й замикала,
Шовковим шнурочком зав''яза(ла).

Ой посидь же, доню, да й у темниці,
Поки й розійдуться вечорни(ці).

Поки й розійдуться да й вечорниці,
Поки ляжуть спати чарівни(ці).

Пусти ж мене, мамо, да й погуляти,
Бо вже чарівниці лягли спа(ти).

Тільки мій миленький по двору ходить,
Вороного коня за повід во(дить).');
