INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8302676','Казкові диво-мандри','Музика: Ірина Музика Слова: Наталя Гуркіна. Виконує: Ірина Музика','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'На подушечці маля
Очка закриває,
Від матусі, татуся
Казочку чекає,
Про сороку-білобоку,
Про царя-жарптицю,
Про немудрого Іванка
І мудру дівицю.

Про негарне каченятко,
Яке гарним стало,
І про дзеркало казкове,
Яке усе знало,
Про ведмедя, про мурашку,
Про слона, синичку,
Про чарівну скатертину
І диво-криничку.
Про маленьке жабенятко,
Про змія страшного,
Про веселого царя
І про царя злого.

На подушечці маленькій
Щастя засинає,
У казкові диво-мандри
