INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_829979','Добрий Вечір Тобі Пане Господарю Радуйся (1)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа (Коляда). Традиції Спасителя і старинна ідея Бога: У старовіцьких Колядках про Почин Світа може не бути спомину про особистого Творця, у деяких лише приспіви з окликами до Бога і Сина Божого. — Не можна бути певним, що вони є пізнішими додатками з доби християнської. Вони якраз роблять вражіння висловлювань мітичного змісту про Сина Божого, хто''зна чи не в зв''язку з традиціями Полудня про Спасителя Світа; але все-таки криється в них, хоч би й старинна, ідея про Бога. Значна частина Колядок, як побачимо опісля з Місячною символікою, має за тему ненастанну творчість "Господа", яка приявлюється у всевідживаючій природі. Вони подобають на реліґійні роздуми з приводу Сотворення Світа, бо вказують на залежність від "Господа" всього життя в природі. І вони по своїй суті — і змістом і формою — належать до Колядок про Почин Світа. Буде в Тебе Господь на Вечері. Стрівся Місяць з Ясною Зорею. Ой там виxодило та Три Товариші. Радуйся Земле Коляда іде! Українське Різдво Світа: Співаймо Колядки й Щедрівки на Щастя-Здоров''я! (Стародавні Колядки й Щедрівки з нотами і звуковими зразками — Мереживний Збірник) Українська Астрально-мітологічна реліґійна концепція. Дрібний Дощенько Сам Милий Господь Бог. Що до Колядок про мітичну Небесну Трійцю, то попри великім числі Колядок про гостину на Свят-Вечер у Господаря — Місяця, Сонця і Дощику, я лиш одну знаю Колядку, що прямо називає Дощик Господом Богом. Записана мною в Конюхах, Бережанського повіту, співає ось як про Святовечірніх Небесних гостей: Встань Господарку довго не лежи УІ. Перший гостенько Ясне й Сонінько Другий гостенько Ясний Місяченько Третий гостенько Дрібний Дощенько Сам Милий Господь Бог У відміні ІІ — Ой у Нашого Господарентя — повище наведених Колядок, замість Дощику являється "сам Біг Небесний". Можна цю відміну зрівняти з ч. ІІІ — В Нашего Брата а в Єго Дворі, а тоді сам Біг Небесний буде намість Ясної Зірнички. Є Колядкові образці, в яких замість Дощику стоять Зорі збірно. Що нарід розуміє під Дощиком з Неба самого Господа — це нормальна Старовіцька ідея, бо Дощик є плодом Неба, а Небо є символом Бога; на цей мітологійний образець будуть наведені аналогії від первісних живучих природних народів. Зоря символом Дощу з Неба. Але Господь на місці Зорі — це мітологійна ідея, виведена послідовно з попередньої. Вона є одною з найцікавіших і найстарших мітологійних ідей Полудневого світа; а в Українців виступає вона в деяких Колядках та у багатьох Щедрівках: Зоря є символом Дощу з Неба. Так у Вавилонців богиня Іштар була символом Вечірньої Зорі і Оживлюючого Дощу. Цілий ряд Щедрівок співає про Небесну Росу або Рясу (Рясну Росу), або рясний животворний Дощик; і алюзіями (натяками) до Зорі або Дівчини як Зорі рівняє ідеологічно Росу і Дощ, — Зорю і Дівчину, — з собою. В Щедрівках ідея спричинення Дощу Зорею розвинена як найдальше, з всякими можливими відтінками (є їх більше, ніж повище наведено). Але в Колядках вона стоїть на первісній основі: Дощ є на місці Господа; а коли Зоря стоїть на місці Дощу, то це вже інша категорія ідей, що є в зв''язку з Щедровечірним ідейним кругом. (Ця Колядка своїм приспівом пов''язує Дрібний Дощ з Нашим Милим Богом на Небеси: Здибаў сьі Місьіць йа з Дрібним Дошчом) Дощик символом Бога Небесного. Очевидно — ідея Дощу і Господа є старша, більше пракультурна, пряма, без усякої хитрости; ідеї Щедровечірні мають вже мітологійну закраску, хоч все-таки дуже первісну. Що "Дощик" в Українського народу є виразно символом Бога Небесного і тому нарід відноситься до нього з реліґійним пієтизмом (побожністю), свідчить найкраще ІУ-а відміна наведених Колядок — Пане Господару вставай с Постелі, де між Небесними гостями, через яких "Рай розвився, Христос родився цьому дому", до котрого вони приходять, — на першім місці і в першій почесті стоїть "Дрібен Дощик". Вислів "Христос родився цьому дому" є без сумніву сполукою первісного і нового ідеалу Бога і збільшує Його почесть. Небо як символ Бога у первісних народів. Додати належить, що Небо як символ Бога є предметом шанування у багатьох первісних народів; особливож в Уралалтайців, пастуших, номадних народів пракультурного округа. Формою і змістом ріжниться цей культ від Українського, але мотив реліґійний є той самий. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Листки з приводу цієї Пісні: Свята, Тайна, Вечеря 6.01 — Як її підготувати і що вона означає? Українська Астрально-мітологічна реліґійна концепція. Бог, Різдво Світа, Дідух і Лицарі. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Українські релігійні роздуми про Бога. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда) ― Святий Збір (Трійця) ― Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло. Доба мистецьких і наукових містифікацій? "Вертеп", що це таке? Замінювали народні пісні схоластичними віршами школи. "Отрадный результат нашего движения к коммунистическому обществу".','Добрий Вечір Тобі Пане Господарю Радуйся

Відміни приспівів:
1. Ой радуйся Земле Син Божий  народився!
2. Ой радуйся Земле Ясен Світ засвітився!
3. Ой радуйся Земле Світ Новий народився!
4. Ой радуйтесь Люде Ясен Світ засвітився!

Вимітайте Двори Новими Мітлами
Печіть Паляниці з Ярої Пшениці
Застеляйте Столи та все Килимами
Xай посядуть звані довгождані Гості

А що Першим гостем то Краснеє Сонце
А що Другим гостем то Ясненький Місяць
А що Третім гостем то Дрібненький Дощик

А що Сонце мовить Людей благословить
То ізрадується й Дитятко маленьке

А що Місяць мовить Звіра благословить
То заворушицця й Звірятко дрібненьке

А що Дощик мовить Поля благословить
Як перейду Яром Польом Господарьом
То заколосицця Жито і Пшениця
Жито і Пшениця й усяка Пашниця','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:narodni'', ''Колядки'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_829979'), datetime('now')),datetime('now'));
