INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8303878','Миколай',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Рип-рип, рип-рип,
Поскрипує сніжок
Стук-стук, стук-стук,
Хтось кличе діток.
Гей, малята, уставайте,
Двері гостю відчиняйте,
Бо приходить Миколай - |
Чемним дітям буде рай! | (2)

Дзелень-дзелень, дзелень-дзелень,
Дзвіночки дзеленчать,
Ту-ру, ту-ру, ангелами сурмять.
Хто побожним був і чемним,
Свято ждав хто недаремно,
Ну, а хто байдикував - |
Той Антипко потішав!   | (2)

Ну-ну, тепер малята, поспішім,
Святого Миколая обступім!
Пісню дзвінко заспіваймо,
Слава Богу - привітаймо,
Миколая ми чекали,     |
Цілий рочок виглядали! | (2)','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8303878'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8303878','Миколай','Рип-рип, рип-рип,
Поскрипує сніжок
Стук-стук, стук-стук,
Хтось кличе діток.
Гей, малята, уставайте,
Двері гостю відчиняйте,
Бо приходить Миколай - |
Чемним дітям буде рай! | (2)

Дзелень-дзелень, дзелень-дзелень,
Дзвіночки дзеленчать,
Ту-ру, ту-ру, ангелами сурмять.
Хто побожним був і чемним,
Свято ждав хто недаремно,
Ну, а хто байдикував - |
Той Антипко потішав!   | (2)

Ну-ну, тепер малята, поспішім,
Святого Миколая обступім!
Пісню дзвінко заспіваймо,
Слава Богу - привітаймо,
Миколая ми чекали,     |
Цілий рочок виглядали! | (2)');
