INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8303409','Пісня "Лісових Мавок"','Музика: Іван Недільський Слова: Леся Храплива','uk','ukr_ssr_1919_1991',NULL,'1947','аудіозапис','Пісня Куріня ст. пластунок "Лісові Мавки" в Ерлянґені, створена на еміґрації 1947 року.','З зелених рін, з долин широких
Ми України Лісові Мавки.
Шуміли сосни нам високі
І колихали буйні потічки.
Пестили нас вкраїнські зорі
І нам світило сонце золоте,
З вітрами грались ми в просторі
І в нас життя кипіло молоде.

Приспів:
Крізь гори і крізь доли
Несем вперед бадьорий спів,
Мавок чарівні хори,
Ми з України йдем лісів!

Крізь чужину сумну, далеку,
Несемо в серці гомін полонин,
І чар лісів, і шум потоків,
І зелень гір, і ширину низин.
Бо прийде час, прийде година,
Ми вернемось в свої буйні ліси,
Пригорне рідна полонина,
Засяє сонце волі і краси.

Приспів.','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8303409'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8303409','Пісня "Лісових Мавок"','З зелених рін, з долин широких
Ми України Лісові Мавки.
Шуміли сосни нам високі
І колихали буйні потічки.
Пестили нас вкраїнські зорі
І нам світило сонце золоте,
З вітрами грались ми в просторі
І в нас життя кипіло молоде.

Приспів:
Крізь гори і крізь доли
Несем вперед бадьорий спів,
Мавок чарівні хори,
Ми з України йдем лісів!

Крізь чужину сумну, далеку,
Несемо в серці гомін полонин,
І чар лісів, і шум потоків,
І зелень гір, і ширину низин.
Бо прийде час, прийде година,
Ми вернемось в свої буйні ліси,
