INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8303415','Марш Крилатих','Музика: Віталій Гайдук Слова: Дмитро Штогрин, Віталій Гайдук','uk','ukr_ssr_1919_1991',NULL,'1946','аудіозапис','Маршова пісня Куріня ст. пластунів "Чота Крилатих", в Авґсбурзі створена 1946 р. на еміґрації.','Гей, у нас крила молоді,
Нащадки ми Крилатих!
Назустріч сонцю лине в світ |
Наша Чота, Чота Крилатих!   | (2)

Приспів:
Нема в нас страху, смуток гасне,
Юнацька радість б''є, дзвенить...
Життя трудне, але прекрасне,
Лиш треба тільки вміти жить!

Нас не злякають вороги,
На спинять жадні перешкоди,
Ми проламаєм всі льоди,     |
Що сковують шляхи свободи!  | (2)

Приспів.

Вже блиснув меч, світ правди знов
На прю стає із темнотою.
Ми Батьківщини чуєм зов:
Пластуне! Будь готов до бою!
Бо тільки сім знаків огненних
В серцях, в Крилатих нас горить -
Ми ж присягли, що ми жертвенно
Для України будем жить!','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8303415'), datetime('now')),datetime('now'));
