INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_830714','Там, на Лемківщині','Музика: Костянтин Павляк Слова: Костянтин Павляк. Виконує: Костянтин Павляк','uk','ukr_ssr_1919_1991',NULL,'1989','1. Аудіо-запис із фестивалю "Червона рута" 1989 року (надав: Anrzej) 2. http://www.lemko.org.ua/guest.php?page=2 3. Аудіо-запис від автора, 2006 рік','Текст записано на слух з аудіо [1], частково виправлено за джерелом 2, уточнено автором. Акорди записано на слух з аудіо [3]. Ось відгук автора пісні зі сторінки: "Мені дуже приємно, що моя пісня стала народною. Чесно кажучи, не сподівався, хоча це не перший випадок з моєї практики. Майже те ж саме трапилося і з виконаною мною в Каневі у 1990 році піснею (автор – черкаський бард Андрій Миколайович Мороз) "Може цього разу станеш вільною, Україно моя, земле рідная...", авторство котрої потім навіщось приписали деякому Олегові Павлишину. Отже, пісня "Там, на Лемківщині..." була написана мною у 1989 чи 1988 році, в м. Черкаси. Батьки мої родом із Лемківщини. Мама Ольга Драган з села Розділля, а батько Степан Павляк з с. Воля Цеклінська, Краківського воєводства. Моя бабуся Ганна Драган була джерелом лемківських пісень, котрі наш родич Ярослав Бодак разом із Михайлом Дзіндзьом записали, зібрали і написали кілька фольклорно-етнографічних робіт, а саме "Лемківське весілля", "Лемківські хрестини", "Кермеш" і ще деякі, котрі я внаслідок свого надто юного на той час віку просто не освоїв. Ці роботи тривалий друкувалися в газеті "Наше Слово" на "Лемківській сторінці". Отже, пісня "Там, на Лемківщині..." була написана майже за реальними подіями мені це все якось насправді наснилося. "Украдені гори" це, звісно, ремінісценція до твору відомого письменника Дмитра Бедзика, котрий якось гостював у моєї бабусі в Бориславі. Я дуже добре пам''ятав розмову бабусі з письменником про назву його книги бабуся сприймала вираз "украдені гори" дуже буквально (вона пережила переселення під час "Вісли"), а Дмитро Бедзик трохи абстрактно і в переносному значенні. Тому я хотів у пісні створити настрій більш буквальний, як у моєї бабусі, а не як у Бедзика, що, скоріше за все, мені вдалося, бо я і сам інколи плакав, коли її виконував. Отже, що трапилося на "Червоній Руті"? Я виконував три пісні, "Про гетьмана Мазепу", "Як гуляли козаки..." і "Там, на Лемківщині". Було вже темно і холодно, я виступав у другій половині, ближче до кінця. Поки очікував на свою чергу, дуже замерз, задубіли і пальці. Приїхав автобус "Ікарус", нам роздали по одній футболці "Українці всіх країв, кохайтеся!" і впустили до середини погрітися. В автобусі я зігрівся і майже заснув. Нарешті настала моя черга. Я вийшов і заспівав "Пісню г. Мазепи", потім став співати другу "Як гуляли козаки...", коли раптом погасло світло і відключилися мікрофони. Зникла електрика. Я, слава Богу, ні на жодну долю секунди не загальмував і доспівав другу пісню. Третьою була "Там, на Лемківщині". Хоча, можливо, порядок я міг і сплутати адже, слава Богу, минуло 17 років. Після мене виступав гурт "Рутенія" (Сухий Анатолій, Костік Єрофєєв, якась дівчина на скрипці..., до речі, мої однофакультетники по КДУ), теж без світла і електрики. Другого дня журі підбивали підсумки нашого туру (авторської пісні), мені дали звання дипломанта за мужність (!!!!), диплом не дали, пообіцяли, що пізніше видадуть інкрустований на дереві. Так я нічого і не дочекався досі. Коротше, всім, хто виступали після мене, також дали дипломи "За мужність", але порівняйте: одна справа, коли ви виходите на сцену і знаєте, що світла нема і не буде, а інша справа, коли все обривається під час вашого виступу, як було у мене. До речі, ніхто переді мною не вибачився за цей інцидент, ніхто не пояснив, чому це трапилося і навіть не запропонували переспівати заново пісню, все-таки, я хапанув зайвого адреналіну. Менше з тим, бачу, що пісня пройшла випробування часом і людям сподобалася, а це є найвища нагорода для мене, як автора. У мене збереглася газета "Наше Слово", тож незабаром я її відсканую і вивішу в Неті. З повагою, Кость ПАВЛЯК. Підбір акордів: bohdanko (pisni.org.ua)','Як часто я бачу вві сні украдені гори,
Котрі стережуть від мене прикордонні дозори,
Я там ніколи не був, й хтозна, чи потраплю коли,
Хоч ще півстоліття тому мої там батьки жили.
Приспів 1:
Там, на Лемківщині, наші місця святі,
Там, на Лемківщині, ще стоять наші хати.
Як ти, Лемківщино, живеш без нас в самоті?
Чи не зогнили, не зоржавіли хрести
На могилах діді-і-ів?
І я ночами не сплю, мов сновида який.
Я знаю - мій шлях туди не буде легкий.
Бо там, де рівняють кордони - там щастя нема,
У нас різні закони, та єднакова тюрма.
Приспів 2:
Але там, на Лемківщині, наші місця святі.
Але там, на Лемківщині, ще стоять наші хати.
Як ти, Лемківщино, живеш без нас в самоті?
Чи не зогнили, не зоржавіли хрести
На могилах дідів?
Ми по світу розкидані, неначе жиди.
Хто дав вам право вершить нашу долю,
наші "старші брати"?
Сповиті гори туманом, хто ж нам їх верне?
Я знаю, десь там, понад Сяном
є ті, що чекають мене...
Приспів 3:
Десь там, на Лемківщині, де стоять наші хати.
Десь там, на Лемківщині, де наші місця святі.
Як ти, Лемківщино, живеш без нас в самоті?
Чи не зогнили, не зоржавіли хрести
На могилах дідів?','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_830714'), datetime('now')),datetime('now'));
