INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_83116','Боже великий, єдиний','Музика: Микола Лисенко Слова: Олександр Кониський. Виконує: Відлуння','uk','ukraine_1991',NULL,NULL,'Співаник Українських Січових Стрільців. Відень, 1918.','Відміна: Боже, Єдиний, Великий, Неньку-Вкраїну храни, Волі та Правди промінням Ти її освіти. Силою Знання Звичаю люд український зміцни. В чистій любові до краю Ти нас, Боже, зрости. Молимось, Боже, Єдиний, Неньку-Вкраїну храни, Всі Свої ласки-щедроти Ти на неї зверни. Дай людям Волю, дай людям Долю, Дай Доброго Світа, Щастя, дай, Боже, Здоров''я і многая, многая літа!','Боже великий, єдиний,
Нам Україну храни,
Волі і світу промінням
Ти її осіни.

Світлом науки і знання
Нас, дітей, просвіти,
В чистій любові до краю,
Ти нас, Боже, зрости.

Молимось, Боже єдиний,
Нам Україну храни,
Всі свої даски й щедроти
Ти на люд наш зверни.

Дай йому волю, дай йому долю,
Дай доброго світу, щастя,
Дай, Боже, народу
І многая, многая літа','[''pisni.org.ua'', ''cat:christian'', ''cat:himny-marshi'', ''cat:patriotic'', ''Пісні на християнську тематику'', ''Гимни та марші'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_83116'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_83116','Боже великий, єдиний','Боже великий, єдиний,
Нам Україну храни,
Волі і світу промінням
Ти її осіни.

Світлом науки і знання
Нас, дітей, просвіти,
В чистій любові до краю,
Ти нас, Боже, зрости.

Молимось, Боже єдиний,
Нам Україну храни,
Всі свої даски й щедроти
Ти на люд наш зверни.

Дай йому волю, дай йому долю,
Дай доброго світу, щастя,
Дай, Боже, народу
І многая, многая літа');
