INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8304450','Згадай, згадай','(Ти в чужині). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Згадай, згадай,
Згадай, згадай,
Як мене ти покохав.
Згадай, згадай,
Згадай, згадай,
Як мене ти обнімав.

Приспів:
Ти говорив         |
Наймиліші слова,   |
Не знала я,        |
Що не буду твоя... | (2)

Ми розійшлись,
Ми розійшлись,
Ми розійшлись назавжди,
Але чому,
Але чому
Ти приснився мені?..

Приспів.

Скажи, чому,
Скажи, чому,
Не цвіте первомай,
Скажи, скажи,
Скажи, скажи,
Чом не сказав ти:
Прощай...

Приспів.','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8304450'), datetime('now')),datetime('now'));
