INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_830575','Пісенька з варіаціями','Музика: Ліля Кобільник Слова: Ліна Костенко. Виконує: Ліля Кобільник','uk','ukraine_1991',NULL,NULL,'1. Аудіо-альбом “Пісні Лілі Кобільник (Співають Ліля та Оленка Кобільник)” (1998). 2. http://www.teolib.h1.ru/Poez/lkost.html',NULL,'І все на світі треба пережити.
І кожен фініш - це, по суті, старт.
І наперед не треба ворожити,
і за минулим плакати не варт.

Тож веселімось, людоньки на людях.
Хай меле млин свою одвічну дерть
Застряло серце, мов осколок, в грудях.
Нічого, все це вилікує смерть.

Хай буде все небачене побачено.
Хай буде все пробачене пробачено.
Хай буде вік прожито як належить.
На жаль, від нас нічого не залежить.

А треба жити. Якось треба жити.
Це зветься досвід, витримка і гарт.
І наперед не треба ворожити.
І за минулим плакати не варт.

Отак, як є. А може бути й гірше.
І може бути зовсім, зовсім зле.
А поки розум од біди не згірк ще, -
не будь рабом і смійся, як Рабле!

Тож веселімось, людоньки на людях.
Хай меле млин свою одвічну дерть
Застряло серце, мов осколок, в грудях.
Нічого, все це вилікує смерть.

Хай буде все небачене побачено.
Хай буде все пробачене пробачено.
Єдине, що від нас залежить, -
принаймні вік прожити як належить','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_830575'), datetime('now')),datetime('now'));
