INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8304910','Виглядаю Миколая','Музика: Наталія Антоник Слова: Наталія Антоник. Виконує: Юлія Солтисяк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вже на небі срібний місяць
Водить зірок череду
І в його чарівнім світлі
По стежинці я іду.
Знов танцюючі сніжинки
Засипають всі сліди,
Я чекаю, виглядаю,
Чи не прийде він сюди.

Приспів:
Миколай, Миколай,      |
Ти до нас завітай!     |
Миколай, Миколай,      |
Ти про нас не забувай! | (2)

Він завжди прийде таємно,
Тільки нічка на поріг.
Поспішає недаремно,
Щоб відвідати усіх.
Він приносить подарунки,
Радість, злагоду, тепло,
А на ранок рясним снігом
Знов доріжки замело.

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:svyatyy-mykolay'', ''Дитячі пісні'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8304910'), datetime('now')),datetime('now'));
