INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831450','Летів Пташок понад Воду (2)','Українська народна пісня. Виконує: Надія Купчинська','uk','ukraine_before_1917',NULL,NULL,NULL,'Пара-Непара — залицяння, любощі: Загадки. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави, загадки: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Були Світилки Яснії Зірки. Качата-Гусята усі Гори вкрили. Сім Загадок загадаю. Відгадаєш моя будеш. Ішов Козак Дорогою Зеленою Дібровою Летів пташок понад воду Летів Пташок понад Воду (2) Ой Ми зіслані на признаванє. А хто любит чужу жену. А там долов під липою Листки з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції. Висловлювання: Храм Добра. Я гадаю, що ціль усіх великих релігійних звичаїв – не строїти великі храми назовні, але творити храми добра та співчуття всередині, в наших серцях. – Далай-лама','Летів Пташок понад Воду
Скаламутив крильми Воду
Поки Дівча Воду брало
Із Романом розмовляло

Ой Дівчино моя Галю
Сім Загадок загадаю
Відгадаєш моя будеш
Не вгадаєш чужа будеш

Ой що росте без Коріння
Ой що сходить без Насіння
Ой що грає Голос має
Ой що плаче Сліз немає

Камінь росте без Коріння
Сонце сходить без Насіння
Скрипка грає Голос має
Серце плаче Сліз немає

Що без ножа Серце крає
Що літає Крил немає
Ой що в Світі найвільніше
Ой що в Світі наймиліше

Тяжке горе Серце крає
Пісня лине Крил немає
Думка в Світі найвільніша
Рідна Хата наймиліша

Думка в Світі найвільніша
Рідна Хата наймиліша','[''pisni.org.ua'', ''cat:kupalski'', ''cat:shchedrivky'', ''Купальські пісні'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_831450'), datetime('now')),datetime('now'));
