INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8314654','Мамо моя, голубко сива','Музика: Іван Кушнір Слова: Іван Кушнір','uk','ukraine_1991',NULL,NULL,NULL,'Пісню виконує Юрій Футуйма.','Залишаю усе, поспішаю до Тебе на свято,
Може зустрічей цих залишилося так не багато...
І колись я прийду, і постукаю тихо до хати,
А мені не відчинить дверей дорога мені мати...

Приспів:
Мамо моя, мамо моя, голубко сива,
Скільки біди, скільки тривог Ти пережила?
Мамо моя, мамо моя, рідна Ти ненько,
Дай я Тобі поклонюся сьогодні низенько!..

Але котиться час і назад повороту немає,
Тобі стільки вже літ, білим снігом голівонька сяє.
Хочу долю вблагать, повернуть Тебе людям на щастя,
Бо ніхто так як Ти не вміє приборкать напасті.

Приспів.

Залишаю усе, поспішаю до Тебе на свято,
День народження в мами, дай же, люба, Тебе обійняти,
Будь завжди дорога і хай вічно ялинові шати
І смереки стоять біля хати твоєї на чатах.

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8314654'), datetime('now')),datetime('now'));
