INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8317950','Осінь на порозі','Музика: Анна Олєйнікова Слова: Анна Олєйнікова. Виконує: Софія Комарова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Осінній дощ в віконечко
Все стукає дрібненько,
За хмарку, видно, сонечко
Сховалося раненько,
Травичка вжухла,
Журавлі курличуть:
Вирій, вирій!...
А я всміхаюсь осені -
Такій сумній і милій.

Приспів:
Літо, літо, ти минуло тихо.
Осінь, осінь стука на поріг...
Листя жовте стелить на дорозі
Осінь, осінь - року оберіг...

Блакитне небо осені,
Останній промінь сонця
Мене загріти вирішив
Та заглянув в віконце,
Осінні жовті кораблі
Пливуть, пливуть усюди,
І літо з ними упливе,
А я чекати буду!..

Приспів.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8317950'), datetime('now')),datetime('now'));
