INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831756','Як ішов я з Дебpечина додому','Українська народна пісня. Виконує: Анатолій Солов''яненко, Віктор Пашник','uk','ukraine_before_1917',NULL,NULL,'1. Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002 2. Перлини української народної пісні. - К.: Музична Україна, 1989','Пара — любощі: Чоpна Куpка. Обійми-поцілунки. Дорога. Вишивання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Кругом Нього зелененько всередині веселенько. Зайшла менi Чоpна Куpа Доpогу. Так ня Мила притискала до себе. Ой продала Дівчина Курку Ой чорна я си чорна Як ішов я з Дебpечина додому Правой ручкою обняла ще й поцілувала. Прийди-прийди Серденя на Пухові Подушки. Шиє-малює Злотом гаптує. Знайшов лем я Вишиваную Хустку. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Про Українські назви місяців Марець і Май. Май. Стежки до листків про Українські пісні.','Як ішов я з Дебpечина до Дому
Зайшла мені Чоpна Кура Доpогу
Iди-iди Чоpна Кура до Дому                   |
Не заважай  не заважай по Доpозі нікому      |(2)

Як ішов я з Дебpечина до Хусту
Знайшов лем я Вишиваную Хустку
Ой чи Мила чи не Мила ю (ї) шила             |
Лем би она лем би она вишиваною была         |(2)

Як ішли ми з Дебречина до Дому
Про той Вечір не розкажем нікому
Так ня Мила притискала до себе               |
Чи любиш мя чи візьмеш мя бо я млію без Тебе |(2)','[''pisni.org.ua'', ''cat:dances'', ''cat:polky'', ''cat:vesnyanky-hayivky'', ''Пісні до танцю'', ''Польки'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_831756'), datetime('now')),datetime('now'));
