INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831474','Козак від’їжджає Дівчинонька плаче','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Пісня повниться Колядними символами й образцями. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Шиє-малює Злотом гаптує. Буду Хуста прати Сріблом-Злотом вишивати. Прийди-прийди Серденя на Пухові Подушки. Козаче-Соколе візьми мене із собою. Козак від''їжджає Дівчинонька плаче. Ой чого Ти Дубе на Яр похилився Ой устань же Козаченьку. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Козак від''їжджає Дівчинонька плаче
Куди їдеш Козаче
Козаче-Соколе  візьми мене із собою
На Вкраїну далеко

Останні два рядки кожної в''язки повторюються.

Що ж будеш робила Дівчинонько Мила
На Вкраїні Далекій
Буду Хуста прати Сріблом-Злотом вишивати
Козаченьку Серденьку

Де ж ти будеш прала Дівчино Кохана
На Вкраїні Далекій
На Крутій Горі тай на Синьому Морі
Козаченьку Серденьку

Де ж будеш сушила Дівчинонько Мила
На Вкраїні Далекій
На Буйнім Вітрочку на Шовковому Шнурочку
Козаченьку Серденьку

Що ж ти будеш їла Дівчинонько Мила
На Вкраїні Далекій
Сухарі з водою аби Милий із Тобою
На Вкраїні Далекій

Де ж ти будеш спала Дівчино Кохана
На Вкраїні Далекій
В Степу під Вербою аби Милий із Тобою
