INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831171','Ой ходить Сон по Вуленьці','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Колискові: Світові-Дитині. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Ходить Котик по Плоточку. Листки з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові. Стежки до листків про Українські традиції. Висловлювання: Відчути і зрозуміти. Цієї години учні наблизилися до Ісуса і сказали йому: "Таки хто найбільший в царстві небесному?". Покликавши дитину, він помістив її серед них і сказав: "Правда, я вам це повідомляю, коли ви не змінитеся і не станете, як діти, ви не ввійдете до царства небесного. Той, хто стане, як ця дитина, ось найбільший в царстві. Хто прихистить в моє ім''я таку дитину, як ця, той прихистить мене самого". – Євангелія (від Матвія)','Ой ходить Сон по Вуленьці
В Тонкій Білій Кошуленьці
Ходи Сонку в Колисоньку
Приспи Мою Дитиноньку
На Котонька Воркотонька
На Дитину Дрімотонька','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_831171'), datetime('now')),datetime('now'));
