INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8319307','Максим Залізняк партизан','(Під Херсоном). Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'смт. Печеніжин','Останні два рядки повторюються, після на повстанську тематику.','Ой, там під Херсоном високії трави,
Ой, там під Херсоном курган,
Лежить в одинокій могилі широкій      |
Максим Залізняк - партизан.           | (2)

Нащо мене куля так рано зранила,
Нащо поранила молодця?
Нащо санітари мене підібрали,         |
Нащо до шпиталю привезли?             | (2)

Лежу я в шпитали, болять мене рани,
Болять мене рани, болять,
Одна нариває, друга заживає,          |
А з третьов прийдеться помирать.      | (2)

Відкрий ми сестричко, долішне віконце,
Най я подивлюся на той фронт,
Як браття воюють, як кров проливають, |
А я тяжко ранений лежу.               | (2)

Подай ми сестричко, білого паперу,
Най я лист напишу до рідні,
Рідня як узнає, що син помирає,       |
Заплаче матуся стара.                 | (2)','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8319307'), datetime('now')),datetime('now'));
