INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8306552','Ішов чумак дорогою',NULL,'uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ішов чумак дорогою
Та й пісню співає,
Другий сидить на важниці,
Важкенько здихає:

"Ой тепер, мій товаришу,
Пропали з долгами:
Проклятії бусурмани
Воли позаймали.

Щo прокляті бусурмани
Воли позаймали,
Туди йшли з волами,
Відтіль - з батогами.

У городі в Камишині
Та крутії гори,-
Щo туди йшли у жупанах,
А звідтіль ідемо голі.

У городі в Камишині
Та жовтії піски,­
Туди йшли з волами,
А відтіля йдемо пішки".

У городі в Камишині
В усі дзвони дзвонять,
Оглянеться старий чумак­
У світ воли гонять.','[''pisni.org.ua'', ''cat:chumacki'', ''Чумацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8306552'), datetime('now')),datetime('now'));
