INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8317501','Наша вчителька','Музика: Анна Олєйнікова Слова: Наталія Іванова. Виконує: Зразковий театр української пісні Джерельце','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Знову дзвоник задзвонив,
Кличе всіх у клас.
Наші парти в три ряди
Зустрічають нас.
Поспішаємо в клас
Без коливань:
Розкриває свій кордон
Нам країна знань.

Приспів:
3 вчителькою нашою
По дорозі знань
Так цікаво мандрувати
З кошиком питань.
Наша вчителька все знає,
Ми - одна сім''я,
В душі дітям засіває
Мудрості зерня.

Сніг летить, а, може,
Дощ ллється за вікном -
З вчителькою нашою
Легко і тепло.
В серці кожному погляд
Із-під вій -
Ніби зітканий з надії
І дитячих мрій.

Приспів.','[''pisni.org.ua'', ''cat:devoted'', ''cat:shkilni'', ''Пісні присвячені окремим особам'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8317501'), datetime('now')),datetime('now'));
