INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8323052','Друзі','Музика: Сергій Замченко Слова: Сергій Замченко','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Сергій Замченко.','Знов зібрались з друзями, сіли у садку.
А поряд зозуленька все "ку-ку" й "ку-ку".
Квіти пахнуть м''ятою, пахощі в гаю -
Сидимо із друзями, наче у раю.        | (2)

Наллємо по чарочці, загудуть столи,
У садочок радість знов друзі принесли,
Притулюсь до яблуньки, вишню обійму,
Повернув садочок знов молодість мою!  | (2)

Сад буяє квітами, пісню в яр несе,
Мов вишнева гілочка, дівча розцвіте,
Літечко за літечком - молодість мине.
Цілуй її миленьку, час тебе не жде.   | (2)

Знов зібрались з друзями, сіли у садку.
А поряд зозуленька все "ку-ку" й "ку-ку".
Квіти пахнуть м''ятою, пахощі в гаю -
Сидимо із друзями, наче у раю.        | (2)

Вже ласкає сонечко яблуньки гілля,
Загуляє з хмаркою вітер до рання.
Знов згадаєм роки ті, молоді літа,
Нам не повернути їх, та в душі весна. | (2)','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8323052'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8323052','Друзі','Знов зібрались з друзями, сіли у садку.
