INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8319910','Випускний вальс','Музика: Віктор Ох Слова: Віктор Фінковський','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'І прийшла довгождана мить,
Серце стукає, тріпотить,
Тут зібралася вся рідня,
Ми чекали так цього дня,
Із шкільного гніздечка ми
Розлітаємось, як птахи.
Випускниці й випускники:
Проминули шкільні роки.

Приспів:
Вальс, неначе, під чарами...
Вальс, як лебеді, парами
Ми назавжди збережемо
До школи любов!..

Проминуло шкільне життя
І попереду майбуття,
Повні задумів та ідей
Ми зустрінем прийдешній день.
Непомітно пролинув час
І залишив на згадку вальс,
Пам''ятаймо шкільні роки,
Випускниці й випускники.

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8319910'), datetime('now')),datetime('now'));
