INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831909','Ой при Лужку при Лужку при Широкім Полі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Розбуджу Солодкий Сон Красную Дівицю — Дівчина збуджує Парубка, а Парубок пробуджує Дівчину. Поцілувати, поцілити чи зцілити? Ціль — ціле? Зцілення — у цілому? Як цілишся — то зцілишся? Хто цілить душу-тіло? Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Кругом Нього зелененько всередині веселенько. Вибирай си кого любиш. Забави з Паруванням, забави з Цілуванням. Правой ручкою обняла ще й поцілувала. Обіймати-цілувати коби лиш допасти. Ой рано-рано Куроньки піли Болить мене головонька ще й межи плечима Верба над Водою Коріння в Долину Дівчино Моя Переяславко І се Село і то Село І учора Горох і сьогодні Горох Ішло Дівча Лучками Ой на Горі Два Дубки Ой при Лужку при Лужку при Широкім Полі Ой у Лісі на Орісі Соловейко щебетав Ой устану ранесенько вмию Личко Білесеньке Переманочко Чорная Галочка Порізала-м Пальчик тай болить (1) Порізала-м Пальчик тай болить (2) Раз якось на Весні крізь Проміння Ясне Тече Вода Каламутна Мила Моя чого-сь смутна Тече Вода Каламутна чого Моя Мила смутна Туман Яром по Долині Чарівна Нічка Землю вкрила Через Річеньку через Болото Чиї Коні на вигоні мої у Садочку Чи тямиш Дівчино той Вечір Чудовий Якби мені не Тиночки тай не Перелази Зайшла менi Чоpна Куpа Доpогу. Так ня Мила притискала до себе. Ой не годен пан Каньовський мене цілувати. Хто ж нас поцілує в уста малинові. Спутай Коня на Отаву в Залізнії Пути. Там то Мамко Мельник! Івана Купала тай в Воду упала. А я Тебе Другою обійму. А пливала Кладочка під Млином Ой виросла Тополя Край Поля Ой нема Ганнусі найгіршої муки А я жала Пшениченьку лиш по Колоскови. Ой дай Дана межи Туденьками Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Рокове Коло. Стежки до листків про Українські традиції. Ще пісні з поцілунками:-) від Сонечка:-)), Богданка, Штика,...: А ти Старий Діду чому ся не жениш? Вон Хлопці вон За тобою Легінику Ой орали хлопці ниву Ой піду я в Полонину Сиджу я край Віконечка Як я Сено грабала А чи вдома Пан Хазяїн В Саду ходила Квіти збирала Горіла Сосна Смерека Дам я Яловицю','Ой при Лужку при Лужку при Широкім Полі
При Великім Табуні Кінь гуля по Волі -2

Кінь гуля по Волі Козак по неволі
Ой впіймаю-загнуздаю Шовковой Уздою -2

Ой впіймаю-загнуздаю Шовковой Уздою
