INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_832518','На Майдані на Риночку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Сосонка-Барвінок-Вогонь. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Закликання Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Стоїть Сосонка в Барвіночку. Кругом Неї Дівки сидять. Були Світилки Яснії Зірки. Кругом Неї Огні горять. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Українська Астрально-мітольоґічна реліґійна концепція. Про Свято Івана Купала Стежки до листків про Українські традиції.','На Майдані на Риночку
Стоїть Сосонка в Барвіночку

Кругом Неї обметено
Барвіночком оплетено

Кругом Неї Огні горять
Кругом Неї Дівки сидять

Туди Хлопці збиралися
На Мед-горілку складалися.

А той Ваня найбільше дав
Бо він Марію сподобав','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_832518'), datetime('now')),datetime('now'));
