INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831312','Що ж і бо і це за Село','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','У східних традиціях є мальовані символи, — напр., йоні/лінґам, — жіночого/ чоловічого начала, дівочої/парубочої сутності, які можуть бути предметом споглядання, медитації. В Українців такі дивовижні символи пісенні. Пара — любощі: Село-Сад-Калина. Радість-Веселість. Еротика, жарти, забави: Катерини –... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... –... Кругом Нього зелененько всередині веселенько. А в Городі а в Городі Роман родить Благослови Мати Весну закликати (2) Вийди вийди Іваночку (2) І се Село і то Село Ішло Дівча Лучками Коло Млина Калина На Нашу Хлопці на Нашу Ой за Лісочком Сонечко встало Ой на Горі Калина Ой на Горі Калина під Горою Малина (1) Ой на Горі Калина під Горою Малина (2) Покотилась по Дорозі Цинова Тарілка Прийшла Весна з Квітками Хтось у Борі гукає Що ж і бо і це за Село Качата-Гусята усі Гори вкрили. Зайшла менi Чоpна Куpа Доpогу. Занадився Журавель до Бабиних Конопель. Вибирай си кого любиш. Правой ручкою обняла ще й поцілувала. Прийди-прийди Серденя на Пухові Подушки. Спутай Коня на Отаву в залізнії пути. Люлька ж моя Червоная звечора курила. Там Мою Грушечку час трясти. Ходить Котик по Плоточку. Ой маю я Пасіку в Лісі. Тай за теє Яблучко Червонесеньке. Чоловіка не позичу ані трошки. До робіт нема сил до молитв нема слів. Там то Мамко Мельник! У Скрипочку грає хороше співає. Хто Дудочку зробив Пісеньку навчив. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Про Українські назви місяців Марець і Май. Май. Стежки до листків про Українські традиції. Заспіваю що минуло, передвіцький згану час. Як весело колись було, як то сумно тепер в нас! – Руслан Шашкевич. Що ж і бо і це за Село -->','Що ж і бо і це за Село    | (2)
Що ви Ньому весело

Кругом Нього Сад-Садовина
Всередині Червона Калина

Кругом Нього зелененько
Всередині веселенько','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_831312'), datetime('now')),datetime('now'));
