INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8321256','Пісня про випускний','Музика: Сергій Недбайло Слова: Сергій Недбайло','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Стояли наші мами
І сумували з нами,
Дитинство безтурботне,
Назавжди прощай!..
До тебе, рідна школо,
Не вернемось ніколи,
Своїх дітей дорослих
Ти не забувай!
І кожен знає із нас -
Це був найкращий наш час!

Приспів:
Нехай нас доля в новий світ понесе!
Через багато літ згадаєм ми все:
Цей вечір п''янкий, дзвінок голосний, |
Це свято - наш випускний!            | (2)

За стільки довгих років
Учителям мороки
Багато завдавали -
Та прощали Ви нас.
Ми всякими бували,
Не раз бешкетували,
Веселим був і дружним
Випускний наш клас.
І наші учителі -
Найкращі ви на Землі!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8321256'), datetime('now')),datetime('now'));
