INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831154','Ходить Котик по Плоточку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Колискові: Світові-Дитині. Пара - любощі: Котик-Плоточок-Хвосточок. Дитина - Дитяточко Маленьке. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Кругом Нього зелененько всередині веселенько. Висіла Колисонька на Шнурку. Ходить Котик по Плоточку. Та б''ють Його по Хвосточку. Котику Сіренький Котику Біленький Люлі Люлі Старий Гулю Ой колишу Дома лишу Дитину Маленьку Ой Ти Коте Марку Ой ходить Сон по Вуленьці Спи Мій Хлопчику Прекрасний Ходить Котик по Плоточку Івана Купала тай в Воду упала. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові. Стежки до листків про Українські традиції. Бути українкою для мене – означає нести всім людям планети стародавні українські пісні, духовні цінності, збережені та помножені нашим народом протягом багатьох тисячоліть. Цінності, які багато людей світу спрагло шукають: кохання, добро, мир, материнство, правду, справедливість, людяність. – Народна співачка.','Ходить Котик по Плоточку
Та б''ють Його по Хвосточку
Ой Люлі-люлі-люлі -2

Цить Котику не воркочи
Бо Дитина спати хоче
Ой Люлі-люлі-люлі -2

Дитяточко Маленьке
Воно спати раденьке
Ой Люлі-люлі-люлі -2','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_831154'), datetime('now')),datetime('now'));
