INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_832358','А в Саду Саду дай Винограду','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Хто і кого просить дати Винограду в Саду-саду? Чим Вишивання нагадує стрій Пісень? Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі)... Великдень... Зелені Свята (Трійця)... Івана Купала... Рокове Коло. Світотворчі містерії. Святе Шиття-Вишивання. Помічення Пари. Шиття-Вишивання символом Світотворення. По чім Його ви так упізнали. Шиє-малює Злотом гаптує. А в Саду Саду дай Винограду Висиділа Квочка Двоє Куряточок Да чому ти Дівчино гуляти не йдеш Ой в Ліску в Ліску на Дубку Ой рано-рано Куроньки піли По Серед Моря стоїть Гоголя Сволока тече в Хаті Болото Там за Горею за Високею Чи Думу Дума Микола Дома Пасла Маланка Два Качура Шовки пряла Шидри ткала. Ой учора а звечора пасла Маланка бай Качура Вже Весна воскресла. З Залуччя до Нігня Ой світи Місяцю на Нашу Вулицю Дівчино Рибчино здорова була Козак від''їжджає Дівчинонька плаче Ой джигуне, джигуне Ой на Горі Нивка Кругом Материнка Ой у Лісі й у Лісі на Дубку Ой чорна я си чорна Як iшов я з Дебpечина додому Ой Данчику Білоданчику поплинь. Ходять наче вишивають. А ми Йому Кінця не знайдем. Ой Вінку Наш Вінку Хрещатий Барвінку. Зайшла менi Чоpна Куpа Доpогу. Знайшов лем я Вишиваную Хустку. Ой маю я Пасіку в Лісі. Ой Кум до Куми залицявся Листки з приводу цієї Пісні: День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Стежки до листків про Українські традиції. Первовічні творчі птиці у вишивках і Щедрівках. Дуже повчаючим для зрозуміння, як сильно перейнявся Український нарід шануванням Первовічних творчих птиць, нерозлучно з своїм Старовіцьким Астральним шануванням, най послужить оце, що він дає вислів одному й другому у своїх символічних, артистичних, красних, вишивках, а навіть згадує про них у Щедрівках. У Щедрівці ч. 737 зо збірки 3. Ходаковського так співається: Ой на Дунаю на Бережку Ой на Дунаю на Бережку Стояла Золота Корабійка В тій Корабійці Красная Панна Шила Брату вишивала Кошульку На ковніри Зора і Місяць На пазушках Райські Пташки На рукавцях Сивці-Голубці На придолі Турі і Олені Як ти Брате будеш женитися Місяць і Зора будуть світити Райськії Пташки будуть щебетати Сивці-Голубці будуть гукати Тури і Олені будуть скакати... (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Див. також Лист о. Кс. Сосенка про вишивки.','А в Саду Саду дай Винограду

Приспів:
Святий Вечір!

Тудою текла Річенька Бистра
По тій Річеньці Огалю пливе
Вишла-вибігла Слична Панночка
Стала Огалю дай промовляти
Пливи-пливи Огалю к Славному Городу
Дай накажи Огалю царям да панам
Царям да панам да міщанським синам
А у пана Івана Хороша Дочка
Хороша Дочка Премудра Швачка
Шиє-малює Злотом гаптує
Що й у Подоли Ясні Соколи
На Рукавцях Райськіє Пташечки
А на Ковнірцях Сизиє Голубці
Сизиє Голубці як не загудуть
Райськіє Пташечки як не зацвілять
Ясниє Соколи як не полетять!','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''Колядки'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_832358'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_832358','А в Саду Саду дай Винограду','А в Саду Саду дай Винограду

