INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8325909','На Івана на Купала','Музика: Валентина Гавріш Слова: Валентина Гавріш','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Поліна Маковійчук.','На Івана на Купала
Я Івана прив''язала,
Прив''язала ще й казала:
Будеш ти моїм на вік.
То-ж як би то так і було,
Вік тебе я не забула
І ще нічка нагадала,
Що тебе я відшукала.

Ой, ти, нічка чарівниця,
Мріям дай моїм здійсниться,
Щоб не взяла плутаниця,
А дала два щастя нам.
Зорі б личко освітили,
Я тебе пізнала б, милий,
Подивитись в твої очі,
Доленьку зустріть в цю ніч,
Але пташка наспівала,
Щоб коханого не взяла,
Його інша відібрала,
Прив''язала на купала...

З доленькою не сварюся,
Я із іншим одружуся,
І зірками обв''яжуся,
До милого пригорнуся.
Буду ніченьку не спати,
Тебе, Йванко мій, шукати,
У росі тебе купати
На Івана в світлу ніч!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8325909'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8325909','На Івана на Купала','На Івана на Купала
Я Івана прив''язала,
Прив''язала ще й казала:
Будеш ти моїм на вік.
То-ж як би то так і було,
Вік тебе я не забула
І ще нічка нагадала,
Що тебе я відшукала.

Ой, ти, нічка чарівниця,
Мріям дай моїм здійсниться,
Щоб не взяла плутаниця,
А дала два щастя нам.
Зорі б личко освітили,
Я тебе пізнала б, милий,
Подивитись в твої очі,
Доленьку зустріть в цю ніч,
Але пташка наспівала,
Щоб коханого не взяла,
Його інша відібрала,
Прив''язала на купала...

З доленькою не сварюся,
Я із іншим одружуся,
І зірками обв''яжуся,
До милого пригорнуся.
Буду ніченьку не спати,
Тебе, Йванко мій, шукати,
У росі тебе купати
На Івана в світлу ніч!');
