INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8321272','Дзвенять дзвінки','Музика: Юрій Чичков Слова: Петро Синявський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Скільки радості, скільки тривог
Знову дарує нам шкільний дзвінок.
Нам за класами крокувати разом з ним,
Десять років, десять весен і зим!

Приспів:
Дзвенять різноголосі дзвінки,
Від Далекого Сходу до Карпат,
І знову до школи, ніби струмочки,
Хвилюючись, наші однолітки поспішають.

Знаємо, дитинство не можна повторити,
Дружби шкільної довіку не забути,
Не забути нам рідних цих стін,
Ні великих, ні великих змін!

Приспів.

Буде самий останній урок,
Буде сумний прощальний дзвінок,
Але він радісно стане знову
Першокласників нових зустрічати!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8321272'), datetime('now')),datetime('now'));
