INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8329070','Ой, вийшов місяць із-за хмари','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1940',NULL,'Уснословесний жанр родинно-побутова пісня Місце побутування с. Лімна, Лімнянська сільрада, Турківський район, Львівська область Респонденти Крись Тетяна Луківна, 1940 р.н., Дністрик Галина Федорівна, 1973 р.н., Кіра Оксана Василівна, 1980 р.н., Рушинець Михайло Гаврилович, 1939 р.н. Збирачі Папіш Марія, Артем''як Мар''яна, Довгань Оксана','Ой вийшов місяць із-за хмари
І всю долину освітив,
Та й освітив він всю долину, |
Де ми кохалися колись.       | (2)

А в тій долині є хатина,
А в тій хаті вогонь горить,
Там мати доню научає         |
Дочка заплакана сидить.      | (2)

Ой, доню, моя рідна доню,
Ти в мене донечка одна,
Усі дівчата заміж вийшли,    |
А ти осталася сама.          | (2)

Ой, мамо, ж моя рідна мамо,
За кого ж мені було йти,
Забрала милого другая,       |
Не можу я його знайти.       | (2)

Нічого в хаті більш не чути,
Лиш тільки чути плач дочки,
На третій вечір за нелюба,   |
Дочка давала рушники.        | (2)

Ой, вийшов місяць із-за хмари,
Та й всю долину освітив,
Та й освітив він цю долину,  |
Де ми кохалися колись.       | (2)

Багато з війська поверталось,
Багато декого нема,
Багато пар ся повінчалося,   |
Ти залишилася сама.          | (2)','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8329070'), datetime('now')),datetime('now'));
