INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_831777','Дрібу Дрібу Дрібушечки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Дрібу Дрібу Дрібушечки — Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Качата-Гусята усі Гори вкрили. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Грають по двоє. Беруться за руки, зближають пальці ніг,
а все тіло відхиляють назад: починають хутко кружляти —
то вправо, то вліво, дрібочучи ногами і примовляючи:

Дрібу-дрібу-дрібушечки
Наївшися Петрушечки
Наївшися Лободи
Гала-Гала до Води !
А я вержу Качурика
По долі Водою
Пливи-пливи Качурику
А я за Тобою !','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_831777'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_831777','Дрібу Дрібу Дрібушечки','Грають по двоє. Беруться за руки, зближають пальці ніг,
а все тіло відхиляють назад: починають хутко кружляти —
то вправо, то вліво, дрібочучи ногами і примовляючи:

Дрібу-дрібу-дрібушечки
Наївшися Петрушечки
Наївшися Лободи
Гала-Гала до Води !
А я вержу Качурика
По долі Водою
Пливи-пливи Качурику
А я за Тобою !');
