INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8321409','Мама','Музика: Віталій Кобринович Слова: Віталій Кобринович','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконують Софія Калита, Каріна Сюсько, Марта Труба.','Краплі щастя по щоці,
Ти найкраща на Землі,
Ти життя мені дала,
Я красу твою взяла.
Мамо, я люблю тебе,
Мамо, я люблю тебе,
Люблю тебе!
Приголубиш, пригорнеш,
В казку нашу поведеш,
Ніжністю переплетеш,
Всі негоди відведеш.
Мамо, я люблю тебе,
Мамо, люблю тебе,
Люблю тебе!

Приспів:
Мамо, я люблю тебе
І про це всі знають,
Мамо, я люблю тебе -
Небеса співають!
В тебе серце золоте,
Врода незрівнянна.
Мамо, я люблю тебе!
Ти найкраща мама!

Як з тобою ми гуляєм -
Заздрять всі мені, я знаю.
Все сміємось, розмовляєм,
Аж душа відпочиває.
Мамо, я люблю тебе,
Мамо, я люблю тебе,
Люблю тебе!
Вчиш мене, як маю жити,
Щоб помилок не робити,
З хлопцями як розмовляти,
Подругам не довіряти,
Мамо, я люблю тебе,
Мамо, я люблю тебе,
Люблю тебе!

Приспів. (2)

Мамо, я люблю тебе!!!

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:pro-batkiv'', ''Дитячі пісні'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8321409'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8321409','Мама','Краплі щастя по щоці,
