INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8317676','Чого ж ти, дівчино?','(Ой чого ти дівчино?). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Чого ж ти, дівчино,
По тім лісі блудиш,
Може ти, дівчино,
Мого сина любиш?

Якби не любила,
То би-м не ходила,
Я за твоїм сином
Бистров річков плила.

Бистров річков плила
Та й в студену воду,
Не так твоїм сином,
Як за його родом.

На тобі, дівчино,
Коня вороного,
Відчепись від мене,
Та й від сина мого.

На коня не сяду,
Конем не поїду,
Твого сина люблю
Та й за нього піду.

Ой, там, на долині,
Василь сіно коситъ,
А йому дівчина
Дитину приноситъ.','[''pisni.org.ua'', ''cat:all-ukraine'', ''Загальноукраїнські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8317676'), datetime('now')),datetime('now'));
