INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_832979','Ой підемо, друже-брате.','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой підемо, друже-брате
Від хати до хати,
своїм браттям (браттям) українцям
Заколядувати.

Ой, колядо-колядонько,
Яка ти нам мила,
Бо Пречиста Діва (Діва) Мати
Сина породила!

Вона Його породила
В місті Вифлеємі.
Засмутився лютий (дуже лютий) Ірод
Аж в Єрусалимі.

А ми гарно колядуймо,
Слава! - заспіваймо,
Народженого (Царя) Ісуса
Щиро всі вітаймо.

Йому поклін, честь і слава,
Він Спаситель світу,
І на небі і на (усій) землі
Від віку до віку!','[''pisni.org.ua'', ''cat:kolyadky'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_832979'), datetime('now')),datetime('now'));
