INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8331603','Мала мати сина','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1981','аудіозапис','Там на Лемковині помедже горами: Туристський пісенник / Упор. Лех Лях [Лех Конопніцький]. – Варшава, 1981. – 62 с.','Мала мати сина та й го оженила,
Молоду невістку дуже не любила.

Виправила мати сина у солдати,
Молоду невістку - зелений льон брати.

Як набереш льону, то прийдеш додому,
Не вибереш льону, не прийдеш додому.

Брала она, брала, в полі ночувала
І на своїм полі топольом зостала.

Вертає син з війска, вступає до хати,
Каже: Добрий вечер, моя стара мати!

Мамо ж моя, мамо, што то за причина,
Же посеред поля росне тополина?

Не питайся, оину, што то за причина,
Бери топір в руки, рубай тополину.

Зарубав він єй раз, она ся схилила,
Зарубав другий раз, она прогварила:

Не рубай мя, мужу, не рубай ня дуже,
Бо я не тополя, лише твоя доля.

Бодай твоїй мамі так легко сконати,
Што нас, молоденьких, з пари розганяти!','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8331603'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8331603','Мала мати сина','Мала мати сина та й го оженила,
