INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8329052','Ой, ви, хлопці, посходіться','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1928',NULL,'Уснословесний жанр повстанська пісня Місце побутування с. Хащів, Хащівська сільрада, Турківський район, Львівська область Респондент Хащівська Марія Василівна, 1928 р.н. Збирачі Вовчак Андрій, Довгалюк Ірина','Ой, ви, хлопці, посходіться,
А ви хлопці посходіться,
З дівчатами полюбітся.    | (2)

Полюбіться, покохайте,
Гарну пісню заспівайте.   | (2)

Заспівайте про руїну,
Про Західну Україну.      | (2)

Десь і славна воювала,
За свій нарід життя дала. | (2)

За свій нарід, за свободу,
За самостійність народу.  | (2)

Ви, дівчата, ви хороші,
Вишивайте хлопцям ноші.   | (2)

Лев і тризуб золотенький,
Україні молоденькій.      | (2)','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8329052'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8329052','Ой, ви, хлопці, посходіться','Ой, ви, хлопці, посходіться,
