INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8332807','Хто, як не ти?','Музика: Христина Соловій Слова: Христина Соловій. Виконує: Христина Соловій','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Хто ми з тобою в цьому світі?..
Хто ти мені, а я тобі?..
Вдихаєм ніжність із повітря,
Як діти граємо в любов...
В зеніті милості і млості
Від світла в темряві на раз,
Що ж ти, закривши свої очі,
Лишаєш серце на показ?..

Приспів:
Хто, як не ти, спалить мости?
Хто ж побудує знов?
Навчи мене жити, як ти,
Щоб не кипіла кров!..
Хто, як не ти, спалить мости?
Хто ж побудує знов?
Навчи мене жити, як ти,
Щоб не кипіла моя кров!..

З тобою важко не зважити,
Від себе нікуди втікти,
Сьогодні свято, завтра втрата,
Сьогодні ми, завтра вони...
І я не знаю, де початок,
І де кінець, не знаєш ти...
На завтра можна не чекати,
Усе що маю - все бери!..

Приспів. (2)','[''pisni.org.ua'', ''cat:lirychni'', ''cat:nostalgia'', ''Пісні про кохання, ліричні'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8332807'), datetime('now')),datetime('now'));
