INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8333714','Що приносить Новий рік?',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Що приносить Новий рік?
Справжнє свято для музик!
Він приносить до оселі
Танці і пісні веселі,
Так приходить Новий рік,
Щасливий рік!

Що приносить Новий рік?
Новорічний торт-пиріг!
І морозиво й горішки,
І цукерок всім хоч трішки,
Так приходить Новий рік,
Щасливий рік!

Що Новий приносить рік?
З ним приходить на поріг
Посмішки облич веселих,
Радість у міста і села! -
Так приходить Новий рік,
Щасливий рік!

Що Новий приносить рік?
Справжнє свято для усіх!
З подарунками торбинки,
Хороводи біля ялинки! -
Так приходить Новий рік,
Щасливий рік!
Так приходить Новий рік,
Щасливий рік!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8333714'), datetime('now')),datetime('now'));
