INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_833409','Пане Господарю вставай з Постелі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Будять же Тебе аж Троє Гостей. Чим ся похвалиш Дробен Дощику. Весна іде Красу несе і тій Красі радіє все. Яка чудова Майська Ніч. Листки з приводу цієї Пісні: Ідея Бога на Свят-Вечер. Українські релігійні роздуми про Бога. Українська Астрально-мітольоґічна реліґійна концепція. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Про Українські назви місяців Марець і Май. Стежки до листків про Українські традиції.','Пане Господарю вставай з Постелі

Приспів:
Ой дай Боже !

Вставай з Постелі одчиняй Двері
Розставляй Столи все Тесовії
Стели Скатертки все Круповії
Клади Калачі з Ярої Пшениці
Будять же Тебе аж Троє Гостей

Що Перший гостьо Ясен Місяцю
А Другий гостьо Красне Сонечко
А Третій гостьо Дробен Дощику

Чим ся похвалиш Ясен Місяцю
Ой як я зійду Коло Півночі
То зрадується ввесь Звір у Лісі
Чумак у Дорозі Худоба в Возі
Худоба в Возі і Риба в Воді

Чим ся похвалиш Красне Сонечко
Ой як зійду в Неділю рано
Задзвонять в церквах церквах костьолах

Чим ся похвалиш Дробен Дощику
Ой як я впаду тричі у Маю
То зрадується Жито-Пшениця
Жито-Пшениця й всяка пашниця

А за цим Словом то бувай здоров
Та не сам з собою з Дітьми Жоною
З Дітьми Жоною та з Челядкою
Та з Челядкою і з Худібкою
Дождали цих Свят святкуйте здорові','[''pisni.org.ua'', ''cat:mifichni'', ''Пісня з міфічними, світотворчими мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_833409'), datetime('now')),datetime('now'));
