INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8334001','Зима','Музика: Ірина Федишин Слова: Ірина Федишин. Виконує: Ірина Федишин','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хтось сідає у авто,
Хтось спішить на потяг,
Загляда мороз в вікно,
Заметі і протяг.
Хтось чекає на гостей,
Хтось стіл накриває,
Але кожен у душі
Свято це чекає!

Приспів:
Зима! Колядує вся родина,
Мама жде додому сина! Зима!
Зима! В небі зірка запалала -
Шлях додому показала! Зима!
Зима зможе нас теплом зігріти,
Бо додому ідуть діти! Зима!
Зима!

За вікном Різдвяна ніч
І не гаснуть зорі,
Снігом замітає все:
І поля й дороги.
На столі - кутя, узвар,
За столом - родина
І чекає мама нас:
На доньку і сина!

Приспів. (2)

Зима! Зима!','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8334001'), datetime('now')),datetime('now'));
