INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8333705','Новий рік!','Музика: Ярослав Зварич Слова: Ярослав Зварич. Виконує: Пори року','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вже минає Рік Старий,
Повернуть його не в силі,
Він недавно був Новим,
Був новим, жаданим, милим!
Стали ми на рік зросліш,
Ми на рік стали мудріші!
Скільки ще Років Нових
Доля нам в житті напише?..

Приспів:
Новий Рік! Новий Рік!
Подаруй нам щастя й долі!
І позбав всіх людей,
Всіх людей від лиха й горя!
Хай здійсняться в житті
Добрі наміри і мрії!
Тішить віра й любов,
Хай не згаснуть надії!

З кожним роком
Швидше й швидше
Час іде, біжить, летить,
Що здавалося далеким -
Перетворюється в мить!..
Ми бажаєм від душі,
Щоб здійснились ваші мрії!
І удача у житті
В вашу сторону повіє!

Приспів.

Речитатив:
Хто народився в Україні,
Живе у рідній, чи у далекій стороні,
Із новорічними святами
Вітати радісно мені!
З наступаючим Новим Роком
І з Різдвом Христовим!

Хочем ми того чи ні,
З року в рік ми теж добрієм
І в останню стару ніч
В невідомість віри мрієм!
Людські долі творить час,
Сподівання, віра й мрії.
Старий рік вже майже згас,
Він дарує нам надію!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8333705'), datetime('now')),datetime('now'));
