INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_833858','Щодрий Вечор Добрий Вечор Василє','Українська народна пісня. Виконує: Гуртоправці, Володар, Володар','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Вечір Добрий подай Пиріг Довгий — Тут також прохання до Щедрого Вечора! Пиріг, сало, ковбаса – все символи Місяця й дитинки:-) Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Радуйся Земле Коляда іде! Пасла Маланка Два Качура Символіка Щедрого Вечера і Василя. Щедрий Вечер зачинається властиво під Новий Рік, 13-14 січня (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Читати листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до інших листків про Українські традиції.','Щодрий Вечор Добрий Вечор Василє

А я щодрую Ковбасу чую

Приспів:
Щодрий Вечор Добрий Вечор Василє.

(Кидай) баляси лізь по Ковбаси
Мати казала щоб дали Сала
Батько сварився щоб не барився

Промовляють гуртом:
Вечір Добрий подай Пиріг Довгий
Хоть горіленький аби ціленький
З руками з ногами щоб бігав за нами!','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_833858'), datetime('now')),datetime('now'));
