INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8338817','Почни з себе','Музика: Вадим Лисиця, Олена Кучер, Анна Трінчер Слова: Олена Кучер. Виконує: Анна Трінчер','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Якщо вважав, що люди різні,
Життя - театр, а очі - призма,
Чому тоді радіє серце,
Коли інше поруч б''ється?..
Коли на колінах вже до Бога
Кричить душа, зірвавши голос,
А вже кінець, а як сказати:
Я ж твоя сестра, брате!?!

Де твоя душа, людство?..
Ми всі забули, хто ми є...
Кожного любов іде в люстро,
Так там і зникає...

Ну хто із нас не хотів змінити
Війну на мир, темінь на світло,
А що з себе треба починати
Ніхто і не хоче визнати.
Бо ми ж всі святі, такі всі чисті,
А правда має гіркий присмак.
Коли чорне серце вже не чує:
Брате, як тебе люблю я! Це ж я!

Humanіty, please no more war,
We have forgotten who we are...
All our love goes іnto the mіrror
And there dіssolved іn the dark...
All our love goes іnto the mіrror
And there dіssolved іn the dark...','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8338817'), datetime('now')),datetime('now'));
