INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8327858','Весільний вельон','Музика: Микола Шевченко Слова: Микола Шевченко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Марина Романович.','Швидкий, веселий
І щасливий добігає день.
Вже майже відгуло
Весільне свято.
Ми обрядових
Заспіваємо пісень,
Бо молода сіда
Вельон-фату знімати...
Витьохкує серденько
І душа, мов завмира,
І гостей
Посерйознішали лиця.
Дівоцтво відпустити,
Раптом надійшла пора,
І враз навік
Дружиною зробиться!

Приспів:
Один лиш раз в житті
Знімати вельона,
Зате цвісти й кохати -
Кожну мить.
Тепер - не наречена ти,
А квітка осяйна,
Жона кохана,
Дай себе сповить!..
Хустина білосніжна
Над вродливим, над чолом
І чоловікові
Ласкаві поцілунки.
Тебе, як рідну,
Рід його стрічатиме добром,
А доля щедро        |
Даруватиме дарунки. | (2)

Мої, подруженьки,
Не плачте, не забуду вас,
Бо на весілля ми
До кожної прийдемо.
Цей білосніжний вельон
Хай усіх накриє нас,
І ми не раз "горіла сосна"
Заведемо.
Обидві мами рідні наші
І дбайливі татусі,
І любі гості дорогі,
Рідня-родина.
Перехопивши подих,
Радо подивіться всі,
Як нашій молодій
Пасує ця хустина!..

Приспів.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8327858'), datetime('now')),datetime('now'));
