INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8339103','Шкода','Музика: Tayanna Слова: Tayanna. Виконує: Tayanna','uk','ukraine_1991',NULL,NULL,'https://www.youtube.com/watch?v=F1sCB3ao4gM','Пісня з нового україномовного альбому Тетяни Решетняк. Пісню виконує Тетяна Решетняк.','Я пила каву
Кожного ранку навпроти
І ти був не проти.
Вдягала щастя
В найкращі шати і знала,
Тобі до вподоби.
І все навколо лиш для нас,
І все світ зупиняв на час,
Кохала, кохала!..
Тобі замало стало, як?.. -
Я мовчки кожен раз питала...

Приспів:
Шкода, що я тебе     |
Любила сильно...     |
Шкода, що ти пустив  |
Усе за вітром...     |
Шкода, заплакані очі |
Дівочі, очі, очі...  | (2)

Я пила каву
Після світанку без тебе,
Дивилась на небо, писала вірші
Пальцем по стелі в холодній,
Самотній пустелі...
І хто сказав, що все для нас,
І все світ зупиняв нам час,
Не знала, не знала,
Але десь глибоко в душі
Я щастя кожен раз бажала
Тобі, тобі, тобі!..

Приспів.

Нащо я тебе любила?..

Приспів.

Шкода...','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8339103'), datetime('now')),datetime('now'));
